INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (1, 'en', 'abandon', 'verb', '/əˈbændən/', '放弃；遗弃', 'to leave somebody/something and not return; to give up something completely', '["The crew abandoned the sinking ship.","She abandoned her plans to go abroad."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (2, 'en', 'abstract', 'adjective', '/ˈæbstrækt/', '抽象的', 'existing in thought or as an idea but not having a physical reality', '["Abstract concepts like justice and freedom are hard to define.","The painting was entirely abstract, with no recognizable shapes."]', 'B2', '["education","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (3, 'en', 'absurd', 'adjective', '/əbˈsɜːrd/', '荒谬的；荒唐的', 'completely ridiculous; not logical or sensible', '["It would be absurd to expect everyone to agree.","The plot of the movie was completely absurd."]', 'B2', '["emotions","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (4, 'en', 'abuse', 'noun', '/əˈbjuːs/', '滥用；虐待', 'the use of something in a way that is wrong or harmful; cruel treatment', '["The abuse of power by officials led to widespread protests.","The charity works to protect children from abuse."]', 'B2', '["law","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (5, 'en', 'accelerate', 'verb', '/əkˈseləreɪt/', '加速；促进', 'to happen or to make something happen faster or earlier than expected', '["The car accelerated smoothly as it entered the motorway.","We need to accelerate the pace of reform."]', 'B2', '["technology","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (6, 'en', 'accumulate', 'verb', '/əˈkjuːmjəleɪt/', '积累；积聚', 'to gradually get more and more of something over a period of time', '["She accumulated a large collection of books over the years.","Dust had accumulated on the shelves during our absence."]', 'B2', '["daily-life","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (7, 'en', 'acknowledge', 'verb', '/əkˈnɒlɪdʒ/', '承认；确认', 'to accept that something is true or exists', '["He acknowledged that he had made a mistake.","She refused to acknowledge his presence in the room."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (8, 'en', 'acquisition', 'noun', '/ˌækwɪˈzɪʃn/', '获得；收购', 'the act of obtaining or buying something, especially property or a company', '["The acquisition of the smaller company took several months.","Language acquisition is easier for young children."]', 'B2', '["business","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (9, 'en', 'adapt', 'verb', '/əˈdæpt/', '适应；改编', 'to change your behaviour in order to deal more successfully with a new situation', '["It took him a while to adapt to his new school.","The novel was adapted for television."]', 'B2', '["daily-life","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (10, 'en', 'adequate', 'adjective', '/ˈædɪkwət/', '足够的；合格的', 'enough in quantity, or good enough in quality, for a particular purpose', '["The room was small but adequate for our needs.","Make sure you allow adequate time for the journey."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (11, 'en', 'advocate', 'verb', '/ˈædvəkeɪt/', '提倡；拥护', 'to support or recommend something publicly', '["She advocates equal rights for all citizens.","Many experts advocate a healthy diet and regular exercise."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (12, 'en', 'aggression', 'noun', '/əˈɡreʃn/', '侵略；攻击性', 'feelings of anger and hatred that may result in threatening or violent behaviour', '["He struggled to control his aggression.","The act of aggression was condemned by the international community."]', 'B2', '["emotions","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (13, 'en', 'allocate', 'verb', '/ˈæləkeɪt/', '分配；拨出', 'to give something officially to somebody/something for a particular purpose', '["The government allocated funds for the new hospital.","Each student was allocated a locker."]', 'B2', '["business","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (14, 'en', 'allowance', 'noun', '/əˈlaʊəns/', '津贴；零用钱', 'an amount of money that is given to somebody regularly or for a particular purpose', '["He receives a monthly allowance from his parents.","The company provides a travel allowance for employees."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (15, 'en', 'ambiguous', 'adjective', '/æmˈbɪɡjuəs/', '模棱两可的；含糊不清的', 'that can be understood in more than one way; having different meanings', '["The wording of the contract was deliberately ambiguous.","His reply was ambiguous and left us confused."]', 'B2', '["communication","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (16, 'en', 'ambition', 'noun', '/æmˈbɪʃn/', '雄心；抱负', 'a strong desire to achieve something, especially success or power', '["Her ambition is to become a surgeon.","He was driven by ambition from an early age."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (17, 'en', 'amend', 'verb', '/əˈmend/', '修改；修正', 'to change a law, document, or statement slightly in order to correct a mistake or improve it', '["The law was amended to include new regulations.","He asked to amend his previous statement."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (18, 'en', 'anticipate', 'verb', '/ænˈtɪsɪpeɪt/', '预期；预料', 'to expect something and prepare for it', '["We anticipate that demand will increase next year.","The police had anticipated trouble at the demonstration."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (19, 'en', 'anxiety', 'noun', '/æŋˈzaɪəti/', '焦虑；不安', 'the state of feeling nervous or worried that something bad is going to happen', '["She felt a growing sense of anxiety before the exam.","His anxiety about the future kept him awake at night."]', 'B2', '["emotions","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (20, 'en', 'apparatus', 'noun', '/ˌæpəˈreɪtəs/', '设备；器械', 'the tools or other pieces of equipment needed for a particular activity or task', '["The laboratory was equipped with modern apparatus.","Firefighters wore breathing apparatus to enter the building."]', 'B2', '["science","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (21, 'en', 'appetite', 'noun', '/ˈæpɪtaɪt/', '食欲；欲望', 'a physical desire for food; a strong desire or liking for something', '["Exercise gave her a good appetite.","He had an insatiable appetite for knowledge."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (22, 'en', 'applaud', 'verb', '/əˈplɔːd/', '鼓掌；赞赏', 'to show approval by clapping hands; to express strong approval of something', '["The audience applauded loudly at the end of the performance.","We applaud the government''s decision to invest in education."]', 'B2', '["arts","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (23, 'en', 'appoint', 'verb', '/əˈpɔɪnt/', '任命；指定', 'to choose somebody for a job or position of responsibility', '["She was appointed as the new head of department.","The committee appointed a time for the next meeting."]', 'B2', '["work","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (24, 'en', 'appreciation', 'noun', '/əˌpriːʃiˈeɪʃn/', '欣赏；感激', 'the feeling of being grateful for something; understanding of the value of something', '["She expressed her appreciation for his help.","The course gave me a greater appreciation of classical music."]', 'B2', '["emotions","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (25, 'en', 'arbitrary', 'adjective', '/ˈɑːrbɪtreri/', '任意的；武断的', 'not seeming to be based on a reason, system, or plan and sometimes seeming unfair', '["The choice of colour was completely arbitrary.","The decision seemed arbitrary and unjust."]', 'B2', '["law","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (26, 'en', 'arise', 'verb', '/əˈraɪz/', '出现；产生', 'to happen; to start to exist or develop', '["A number of problems arose during the project.","Should the need arise, we can hire extra staff."]', 'B2', '["daily-life","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (27, 'en', 'aspect', 'noun', '/ˈæspekt/', '方面；层面', 'a particular part or feature of a situation, plan, or subject', '["We need to consider every aspect of the problem.","The book covers all aspects of city life."]', 'B2', '["education","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (28, 'en', 'assert', 'verb', '/əˈsɜːrt/', '断言；主张', 'to state something clearly and firmly as being true', '["He asserted that he was innocent of the charges.","She asserted her right to make her own decisions."]', 'B2', '["communication","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (29, 'en', 'assess', 'verb', '/əˈses/', '评估；评价', 'to make a judgement about the nature or quality of something', '["It is difficult to assess the impact of the new law.","Students are assessed through a combination of exams and coursework."]', 'B2', '["education","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (30, 'en', 'assumption', 'noun', '/əˈsʌmpʃn/', '假设；假定', 'a belief or feeling that something is true or that something will happen, although there is no proof', '["We are working on the assumption that everyone invited will attend.","It is a common assumption that money brings happiness."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (31, 'en', 'assure', 'verb', '/əˈʃʊr/', '保证；使确信', 'to tell somebody that something is definitely true or is definitely going to happen', '["I assure you that the matter will be dealt with promptly.","He assured her of his full support."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (32, 'en', 'attachment', 'noun', '/əˈtætʃmənt/', '附件；依恋', 'a strong feeling of affection for somebody/something; a file sent with an email', '["She felt a deep attachment to her childhood home.","Please find the report as an attachment to this email."]', 'B2', '["relationships","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (33, 'en', 'attain', 'verb', '/əˈteɪn/', '达到；获得', 'to succeed in getting something, usually after a lot of effort', '["She attained the highest grade in the class.","He attained the rank of colonel before retiring."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (34, 'en', 'authentic', 'adjective', '/ɔːˈθentɪk/', '真正的；真实的', 'known to be real and genuine and not a copy', '["The painting was confirmed to be an authentic Picasso.","The restaurant serves authentic Italian cuisine."]', 'B2', '["arts","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (35, 'en', 'authorize', 'verb', '/ˈɔːθəraɪz/', '授权；批准', 'to give official permission for something, or for somebody to do something', '["Only the manager is authorized to sign contracts.","The government authorized the use of military force."]', 'B2', '["law","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (36, 'en', 'awkward', 'adjective', '/ˈɔːkwərd/', '尴尬的；笨拙的', 'making you feel embarrassed; difficult to deal with', '["There was an awkward silence after he finished speaking.","The box was an awkward shape to carry."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (37, 'en', 'barrier', 'noun', '/ˈbæriər/', '障碍；屏障', 'a problem, rule, or situation that prevents somebody from doing something', '["Language is often a barrier to communication.","The government wants to remove trade barriers."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (38, 'en', 'behalf', 'noun', '/bɪˈhɑːf/', '代表；利益', 'in the interests of; as a representative of', '["On behalf of the entire team, I would like to thank you.","The lawyer spoke on behalf of his client."]', 'B2', '["law","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (39, 'en', 'bias', 'noun', '/ˈbaɪəs/', '偏见；偏向', 'a strong feeling in favour of or against one group of people or one side in an argument', '["The report showed clear bias against women.","Journalists must avoid political bias in their reporting."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (40, 'en', 'bold', 'adjective', '/bəʊld/', '大胆的；醒目的', 'brave and confident; not afraid to say what you feel', '["It was a bold decision to expand overseas.","She made a bold statement about the company''s future."]', 'B2', '["emotions","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (41, 'en', 'boom', 'noun', '/buːm/', '繁荣；激增', 'a sudden increase in trade and economic activity; a period of wealth and success', '["The technology boom created thousands of new jobs.","House prices rose sharply during the property boom."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (42, 'en', 'breach', 'noun', '/briːtʃ/', '违反；缺口', 'a failure to do something that must be done by law; an act of breaking a rule or agreement', '["This is a clear breach of the contract.","The data breach affected millions of customers."]', 'B2', '["law","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (43, 'en', 'breakthrough', 'noun', '/ˈbreɪkθruː/', '突破；重大进展', 'an important development that may lead to an achievement or solution', '["Scientists have made a major breakthrough in cancer research.","The negotiations led to a diplomatic breakthrough."]', 'B2', '["science","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (44, 'en', 'burden', 'noun', '/ˈbɜːrdn/', '负担；重荷', 'a duty, responsibility, etc. that causes worry, difficulty, or hard work', '["The tax burden falls most heavily on the poor.","She didn''t want to be a burden on her family."]', 'B2', '["society","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (45, 'en', 'bureaucracy', 'noun', '/bjʊˈrɒkrəsi/', '官僚主义；官僚机构', 'the system of official rules and ways of doing things that a government or organization has', '["The project was delayed by unnecessary bureaucracy.","We need to cut through the bureaucracy to get things done."]', 'B2', '["politics","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (46, 'en', 'capability', 'noun', '/ˌkeɪpəˈbɪləti/', '能力；才能', 'the ability or qualities necessary to do something', '["The country has the capability to produce nuclear weapons.","She has the capability to become an excellent leader."]', 'B2', '["work","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (47, 'en', 'carbon', 'noun', '/ˈkɑːrbən/', '碳', 'a chemical element that is found in all living things and in its pure form as diamond and graphite', '["We need to reduce our carbon emissions.","Carbon dioxide is a major greenhouse gas."]', 'B2', '["environment","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (48, 'en', 'chaos', 'noun', '/ˈkeɪɒs/', '混乱；混沌', 'a state of complete confusion and disorder', '["The country was plunged into chaos after the coup.","The traffic was in complete chaos due to the accident."]', 'B2', '["society","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (49, 'en', 'chronic', 'adjective', '/ˈkrɒnɪk/', '慢性的；长期的', 'lasting for a long time; difficult to cure or get rid of', '["She suffers from chronic back pain.","Chronic unemployment remains a serious problem in the region."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (50, 'en', 'circulate', 'verb', '/ˈsɜːrkjəleɪt/', '流通；传播', 'to move around continuously; to pass from one person or place to another', '["Blood circulates through the body.","Rumours began to circulate about the company''s financial troubles."]', 'B2', '["communication","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (51, 'en', 'cite', 'verb', '/saɪt/', '引用；提及', 'to mention something as a reason or an example, or in order to support what you are saying', '["She cited several studies to support her argument.","He was cited for bravery during the war."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (52, 'en', 'civilian', 'noun', '/sɪˈvɪliən/', '平民；百姓', 'a person who is not a member of the armed forces or the police', '["Many civilians were killed during the conflict.","The soldiers were dressed in civilian clothes."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (53, 'en', 'clarify', 'verb', '/ˈklærəfaɪ/', '澄清；阐明', 'to make something clearer or easier to understand', '["Could you clarify what you mean by that?","The spokesperson clarified the government''s position on the issue."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (54, 'en', 'clause', 'noun', '/klɔːz/', '条款；从句', 'an item in a legal document that says something must or must not be done', '["There is a clause in the contract about working hours.","The escape clause allows either party to withdraw."]', 'B2', '["law","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (55, 'en', 'coalition', 'noun', '/ˌkəʊəˈlɪʃn/', '联盟；联合', 'a government formed by two or more political parties working together; a group of people who join together for a common purpose', '["The two parties formed a coalition government.","A coalition of environmental groups campaigned against the project."]', 'B2', '["politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (56, 'en', 'cognitive', 'adjective', '/ˈkɒɡnətɪv/', '认知的', 'connected with mental processes of understanding', '["Cognitive skills develop rapidly in early childhood.","The disease causes a decline in cognitive function."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (57, 'en', 'coincide', 'verb', '/ˌkəʊɪnˈsaɪd/', '同时发生；一致', 'to take place at the same time; to be the same or similar', '["The festival coincides with the school holidays.","Her account of what happened coincided with his."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (58, 'en', 'colleague', 'noun', '/ˈkɒliːɡ/', '同事', 'a person that you work with, especially in a profession or a business', '["She discussed the project with her colleagues.","He is well respected by his colleagues."]', 'B2', '["work","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (59, 'en', 'commence', 'verb', '/kəˈmens/', '开始；着手', 'to begin to happen; to begin something', '["The ceremony will commence at ten o''clock.","She commenced work on the project immediately."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (60, 'en', 'commentary', 'noun', '/ˈkɒməntri/', '评论；解说', 'a spoken description of an event that is given while it is happening; a written explanation or discussion', '["He provided live commentary on the football match.","The book offers a detailed commentary on modern society."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (61, 'en', 'commerce', 'noun', '/ˈkɒmɜːrs/', '商业；贸易', 'trade, especially between countries; the buying and selling of goods and services', '["International commerce has grown rapidly in recent years.","The chamber of commerce supports local businesses."]', 'B2', '["business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (62, 'en', 'commission', 'noun', '/kəˈmɪʃn/', '委员会；佣金', 'an official group of people who have been given responsibility to control something or to find out about something', '["The government set up a commission to investigate the disaster.","She earns a commission on every sale she makes."]', 'B2', '["politics","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (63, 'en', 'commitment', 'noun', '/kəˈmɪtmənt/', '承诺；投入', 'a promise or firm decision to do something; willingness to give your time and energy to something', '["The company made a commitment to reduce its carbon footprint.","Teaching requires a strong commitment to helping students learn."]', 'B2', '["work","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (64, 'en', 'commodity', 'noun', '/kəˈmɒdəti/', '商品；日用品', 'a product or a raw material that can be bought and sold', '["Oil is one of the world''s most valuable commodities.","Basic commodities like rice and wheat have risen in price."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (65, 'en', 'companion', 'noun', '/kəmˈpæniən/', '同伴；伙伴', 'a person or animal you travel with or spend a lot of time with', '["His dog was his constant companion.","She made a wonderful travelling companion."]', 'B2', '["relationships","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (66, 'en', 'compel', 'verb', '/kəmˈpel/', '强迫；迫使', 'to force somebody to do something; to make something necessary', '["The law compels employers to provide safe working conditions.","He felt compelled to speak out against the injustice."]', 'B2', '["law","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (67, 'en', 'compensate', 'verb', '/ˈkɒmpenseɪt/', '补偿；弥补', 'to provide something good to balance or reduce the bad effects of something', '["The company compensated the workers for their injuries.","Nothing can compensate for the loss of a loved one."]', 'B2', '["business","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (68, 'en', 'competent', 'adjective', '/ˈkɒmpɪtənt/', '有能力的；胜任的', 'having enough skill or knowledge to do something well', '["She is a highly competent manager.","You need to be competent in at least two languages."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (69, 'en', 'compile', 'verb', '/kəmˈpaɪl/', '编纂；汇编', 'to produce a book, list, or report by bringing together different items, articles, or pieces of information', '["She compiled a list of all the participants.","The report was compiled from data collected over five years."]', 'B2', '["education","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (70, 'en', 'complement', 'verb', '/ˈkɒmplɪment/', '补充；使完善', 'to add to something in a way that improves it or makes it more attractive', '["The wine complemented the food perfectly.","The two systems complement each other well."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (71, 'en', 'complexity', 'noun', '/kəmˈpleksəti/', '复杂性', 'the state of being made up of many parts and being difficult to understand', '["The complexity of the problem requires careful analysis.","He failed to grasp the complexity of the situation."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (72, 'en', 'comply', 'verb', '/kəmˈplaɪ/', '遵守；服从', 'to obey a rule, an order, etc.', '["All companies must comply with health and safety regulations.","He refused to comply with the court order."]', 'B2', '["law","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (73, 'en', 'comprehensive', 'adjective', '/ˌkɒmprɪˈhensɪv/', '全面的；综合的', 'including all, or almost all, the items, details, facts, or information that may be involved', '["We offer a comprehensive range of services.","The report provides a comprehensive overview of the market."]', 'B2', '["education","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (74, 'en', 'compromise', 'noun', '/ˈkɒmprəmaɪz/', '妥协；折中', 'an agreement made between two sides in which each side gives up some of the things they want', '["After long negotiations, they reached a compromise.","Neither side was willing to make a compromise."]', 'B2', '["politics","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (75, 'en', 'conceive', 'verb', '/kənˈsiːv/', '构想；设想', 'to form an idea, a plan, etc. in your mind; to imagine something', '["He could not conceive of a world without music.","The project was originally conceived as a small experiment."]', 'B2', '["emotions","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (76, 'en', 'concrete', 'adjective', '/ˈkɒŋkriːt/', '具体的；实在的', 'based on facts, not on ideas or guesses; definite and specific', '["We need concrete evidence before we can act.","Do you have any concrete proposals for reform?"]', 'B2', '["communication","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (77, 'en', 'condemn', 'verb', '/kənˈdem/', '谴责；判刑', 'to express very strong disapproval of somebody/something', '["The government condemned the terrorist attack.","He was condemned to life in prison."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (78, 'en', 'confine', 'verb', '/kənˈfaɪn/', '限制；关押', 'to keep somebody/something inside the limits of a particular activity, subject, or area', '["The discussion should be confined to the topic at hand.","The prisoners were confined to their cells."]', 'B2', '["law","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (79, 'en', 'conform', 'verb', '/kənˈfɔːrm/', '遵从；符合', 'to behave and think in the same way as most other people in a group or society', '["There is pressure on young people to conform.","The building does not conform to safety regulations."]', 'B2', '["society","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (80, 'en', 'confront', 'verb', '/kənˈfrʌnt/', '面对；对抗', 'to deal with a problem or difficult situation; to face somebody that you do not want to meet', '["She decided to confront her fears.","We are confronted with a serious environmental crisis."]', 'B2', '["emotions","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (81, 'en', 'conscience', 'noun', '/ˈkɒnʃəns/', '良心；良知', 'the part of your mind that tells you whether your actions are right or wrong', '["He had a guilty conscience about lying to his friend.","She acted according to her conscience."]', 'B2', '["emotions","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (82, 'en', 'consensus', 'noun', '/kənˈsensəs/', '共识；一致意见', 'an opinion that all members of a group agree with', '["There is a general consensus that education needs to be improved.","The committee failed to reach a consensus."]', 'B2', '["politics","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (83, 'en', 'consent', 'noun', '/kənˈsent/', '同意；许可', 'permission to do something, especially given by somebody in authority', '["Children under 16 cannot give consent for medical treatment.","He gave his written consent to the arrangement."]', 'B2', '["law","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (84, 'en', 'conservation', 'noun', '/ˌkɒnsəˈveɪʃn/', '保护；保存', 'the protection of the natural environment; prevention of loss or waste', '["Wildlife conservation is essential for maintaining biodiversity.","Energy conservation can help reduce utility bills."]', 'B2', '["environment","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (85, 'en', 'consistent', 'adjective', '/kənˈsɪstənt/', '一致的；始终如一的', 'always behaving in the same way, or having the same opinions or standards', '["Her work has been of a consistently high standard.","The results are consistent with earlier research."]', 'B2', '["science","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (86, 'en', 'constitute', 'verb', '/ˈkɒnstɪtjuːt/', '构成；组成', 'to be the parts that together form something; to be considered to be something', '["Women constitute over 50% of the population.","This does not constitute a breach of the law."]', 'B2', '["law","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (87, 'en', 'consult', 'verb', '/kənˈsʌlt/', '咨询；查阅', 'to go to somebody for information or advice; to look something up in a book, etc.', '["You should consult a doctor if the symptoms persist.","She consulted the dictionary for the meaning of the word."]', 'B2', '["health","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (88, 'en', 'contemplate', 'verb', '/ˈkɒntəmpleɪt/', '沉思；考虑', 'to think about whether you should do something, or how to do something', '["She contemplated leaving her job.","He sat by the lake, contemplating the beauty of nature."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (89, 'en', 'contempt', 'noun', '/kənˈtempt/', '蔑视；轻视', 'the feeling that somebody/something is without value and deserves no respect', '["She looked at him with contempt.","He held the rules in contempt."]', 'B2', '["emotions","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (90, 'en', 'contradiction', 'noun', '/ˌkɒntrəˈdɪkʃn/', '矛盾；反驳', 'a lack of agreement between facts, opinions, or actions', '["There is a contradiction between what he says and what he does.","The statement is full of contradictions."]', 'B2', '["communication","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (91, 'en', 'contrary', 'adjective', '/ˈkɒntrəri/', '相反的；对立的', 'opposite in nature, direction, or meaning', '["Contrary to popular belief, the earth is not perfectly round.","The results were contrary to expectations."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (92, 'en', 'controversy', 'noun', '/ˈkɒntrəvɜːrsi/', '争议；争论', 'public discussion and argument about something that many people strongly disagree about', '["The new policy has caused a lot of controversy.","There is considerable controversy surrounding the use of AI."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (93, 'en', 'convention', 'noun', '/kənˈvenʃn/', '惯例；大会', 'the way in which something is done that most people in a society expect and consider to be polite or the right way', '["It is a convention to shake hands when you meet someone.","The party held its annual convention in Chicago."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (94, 'en', 'convey', 'verb', '/kənˈveɪ/', '传达；表达', 'to make ideas, feelings, etc. known to somebody', '["Please convey my best wishes to your family.","The film conveys a powerful message about justice."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (95, 'en', 'cooperate', 'verb', '/kəʊˈɒpəreɪt/', '合作；配合', 'to work together with somebody else in order to achieve something', '["The two companies agreed to cooperate on the project.","The suspect refused to cooperate with the police."]', 'B2', '["work","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (96, 'en', 'correspond', 'verb', '/ˌkɒrɪˈspɒnd/', '通信；相当', 'to be the same as or match something; to exchange letters with somebody', '["The two accounts of the event do not correspond.","She corresponded regularly with friends abroad."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (97, 'en', 'corruption', 'noun', '/kəˈrʌpʃn/', '腐败；贪污', 'dishonest or illegal behaviour, especially by people in positions of power', '["The country has a long history of political corruption.","Anti-corruption measures have been strengthened."]', 'B2', '["politics","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (98, 'en', 'counsellor', 'noun', '/ˈkaʊnsələr/', '顾问；辅导员', 'a person who has been trained to advise people with problems, especially personal problems', '["She went to see a counsellor about her anxiety.","The school employs a full-time counsellor for students."]', 'B2', '["health","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (99, 'en', 'counterpart', 'noun', '/ˈkaʊntəpɑːrt/', '对应的人或物', 'a person or thing that has the same position or function as somebody/something else in a different situation', '["The minister met with her counterpart in the neighbouring country.","The American dollar and its European counterpart, the euro, both fell in value."]', 'B2', '["politics","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (100, 'en', 'crawl', 'verb', '/krɔːl/', '爬行；缓慢移动', 'to move forward on your hands and knees; to move slowly', '["The baby started to crawl at nine months.","Traffic was crawling along the motorway."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (101, 'en', 'crucial', 'adjective', '/ˈkruːʃl/', '至关重要的', 'extremely important, because it will affect other things', '["Timing is crucial to the success of the plan.","It is crucial that we act now to protect the environment."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (102, 'en', 'curriculum', 'noun', '/kəˈrɪkjələm/', '课程；课程设置', 'the subjects that are included in a course of study or taught in a school, college, etc.', '["Foreign languages are part of the school curriculum.","The university has updated its curriculum to include more practical skills."]', 'B2', '["education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (103, 'en', 'deadline', 'noun', '/ˈdedlaɪn/', '截止日期', 'a point in time by which something must be done', '["The deadline for applications is the end of the month.","We are working hard to meet the deadline."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (104, 'en', 'debate', 'noun', '/dɪˈbeɪt/', '辩论；讨论', 'a formal discussion of an issue at a public meeting or in a parliament', '["There has been much debate about the new education policy.","The candidates took part in a televised debate."]', 'B2', '["politics","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (105, 'en', 'debut', 'noun', '/ˈdeɪbjuː/', '首次亮相；处女作', 'the first public appearance of a performer, sports player, etc.', '["She made her debut on the London stage in 2018.","His debut novel was a huge success."]', 'B2', '["arts","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (106, 'en', 'deceive', 'verb', '/dɪˈsiːv/', '欺骗；蒙蔽', 'to make somebody believe something that is not true', '["She had been deceived by his charming manner.","Don''t be deceived by appearances."]', 'B2', '["relationships","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (107, 'en', 'decisive', 'adjective', '/dɪˈsaɪsɪv/', '决定性的；果断的', 'very important for the final result of a particular situation; able to decide things quickly', '["This was the decisive moment of the game.","A good manager needs to be decisive."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (108, 'en', 'declaration', 'noun', '/ˌdekləˈreɪʃn/', '宣言；声明', 'an official or formal statement, especially about the plans of a government or an organization', '["The declaration of independence was signed in 1776.","He made a declaration of his love for her."]', 'B2', '["politics","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (109, 'en', 'decline', 'verb', '/dɪˈklaɪn/', '下降；拒绝', 'to become smaller, fewer, weaker, etc.; to refuse politely', '["The number of tourists has declined significantly.","She declined the invitation to dinner."]', 'B2', '["business","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (110, 'en', 'dedicate', 'verb', '/ˈdedɪkeɪt/', '奉献；致力于', 'to give a lot of your time and effort to a particular activity or purpose', '["She dedicated her life to helping the poor.","The book is dedicated to his mother."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (111, 'en', 'deficit', 'noun', '/ˈdefɪsɪt/', '赤字；亏损', 'the amount by which money spent or owed is greater than money earned', '["The government is trying to reduce the budget deficit.","The company reported a deficit of ten million dollars."]', 'B2', '["business","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (112, 'en', 'democracy', 'noun', '/dɪˈmɒkrəsi/', '民主；民主制度', 'a system of government in which all the people of a country can vote to elect their representatives', '["The country made the transition to democracy in the 1990s.","Democracy depends on the participation of citizens."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (113, 'en', 'demographic', 'adjective', '/ˌdeməˈɡræfɪk/', '人口统计的', 'relating to the study of changes in the number of births, deaths, diseases, etc. in a community', '["Demographic changes are affecting the labour market.","The company analysed the demographic data before launching the product."]', 'B2', '["society","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (114, 'en', 'demonstrate', 'verb', '/ˈdemənstreɪt/', '证明；演示', 'to show something clearly by giving proof or evidence; to show how something works', '["The experiment demonstrates the effects of pollution on plant growth.","She demonstrated how to use the new software."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (115, 'en', 'derive', 'verb', '/dɪˈraɪv/', '源于；获得', 'to come or develop from something; to get something from something', '["The word derives from Latin.","He derives great pleasure from reading."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (116, 'en', 'despite', 'preposition', '/dɪˈspaɪt/', '尽管；虽然', 'used to say that something happened or is true although something else might have prevented it', '["Despite the rain, we enjoyed the trip.","She got the job despite having no experience."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (117, 'en', 'detect', 'verb', '/dɪˈtekt/', '发现；侦测', 'to discover or notice something, especially something that is not easy to see, hear, etc.', '["The tests detected traces of poison in the blood.","I detected a note of sadness in her voice."]', 'B2', '["science","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (118, 'en', 'determination', 'noun', '/dɪˌtɜːrmɪˈneɪʃn/', '决心；毅力', 'the quality that makes you continue trying to do something even when this is difficult', '["She showed great determination in overcoming her disability.","His determination to succeed impressed everyone."]', 'B2', '["emotions","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (119, 'en', 'dialogue', 'noun', '/ˈdaɪəlɒɡ/', '对话；对白', 'conversations in a book, play, or film; a formal discussion between two groups or countries', '["The dialogue in the film was witty and natural.","The two sides agreed to open a dialogue on trade issues."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (120, 'en', 'diminish', 'verb', '/dɪˈmɪnɪʃ/', '减少；缩小', 'to become or to make something become smaller, weaker, etc.', '["The world''s rainforests are diminishing at an alarming rate.","Nothing could diminish her enthusiasm for the project."]', 'B2', '["environment","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (121, 'en', 'diplomatic', 'adjective', '/ˌdɪpləˈmætɪk/', '外交的；圆滑的', 'connected with managing relations between countries; having skill in dealing with people', '["The two countries restored diplomatic relations.","She gave a diplomatic answer to avoid offending anyone."]', 'B2', '["politics","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (122, 'en', 'disability', 'noun', '/ˌdɪsəˈbɪləti/', '残疾；障碍', 'a physical or mental condition that limits a person''s movements, senses, or activities', '["The building has been adapted for people with disabilities.","Learning disabilities affect a significant number of children."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (123, 'en', 'discipline', 'noun', '/ˈdɪsəplɪn/', '纪律；学科', 'the practice of training people to obey rules and orders; a particular area of knowledge or study', '["The school has strict discipline.","Psychology is a relatively new academic discipline."]', 'B2', '["education","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (124, 'en', 'disclose', 'verb', '/dɪsˈkləʊz/', '揭露；公开', 'to give somebody information about something, especially something that was previously secret', '["The company refused to disclose details of the agreement.","He disclosed that he had been in prison."]', 'B2', '["communication","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (125, 'en', 'discrimination', 'noun', '/dɪˌskrɪmɪˈneɪʃn/', '歧视；辨别', 'the practice of treating somebody or a particular group of people less fairly than other people', '["Racial discrimination is against the law.","The company has a policy against gender discrimination."]', 'B2', '["society","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (126, 'en', 'dismiss', 'verb', '/dɪsˈmɪs/', '解雇；驳回', 'to decide that somebody/something is not important and not worth thinking about; to remove somebody from their job', '["He dismissed the idea as impractical.","She was dismissed from her position without warning."]', 'B2', '["work","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (127, 'en', 'disorder', 'noun', '/dɪsˈɔːrdər/', '混乱；失调', 'an untidy state; a lack of order; an illness that causes a part of the body to stop functioning correctly', '["The room was in complete disorder.","She suffers from an eating disorder."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (128, 'en', 'displace', 'verb', '/dɪsˈpleɪs/', '取代；使流离失所', 'to take the place of somebody/something; to force people to leave their home', '["Computers have displaced typewriters in most offices.","Thousands of people were displaced by the flooding."]', 'B2', '["society","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (129, 'en', 'disposal', 'noun', '/dɪˈspəʊzl/', '处理；处置', 'the act of getting rid of something; the fact of having something available to use', '["The safe disposal of nuclear waste is a major concern.","I have a car at my disposal."]', 'B2', '["environment","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (130, 'en', 'dispute', 'noun', '/dɪˈspjuːt/', '争端；纠纷', 'an argument or a disagreement between two people, groups, or countries', '["The workers are in dispute with management over pay.","The border dispute has lasted for decades."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (131, 'en', 'distinction', 'noun', '/dɪˈstɪŋkʃn/', '区别；卓越', 'a clear difference or contrast between people or things', '["We need to make a distinction between the two concepts.","She graduated with distinction from the university."]', 'B2', '["education","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (132, 'en', 'distort', 'verb', '/dɪˈstɔːrt/', '扭曲；歪曲', 'to change the shape, appearance, or sound of something so that it is strange or not clear; to report something in a way that is not accurate', '["The mirror distorted her reflection.","The media distorted the facts to create a sensational story."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (133, 'en', 'divert', 'verb', '/daɪˈvɜːrt/', '转移；使转向', 'to make somebody/something change direction; to take somebody''s attention away from something', '["Traffic was diverted to avoid the accident.","He tried to divert attention from his own mistakes."]', 'B2', '["travel","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (134, 'en', 'doctrine', 'noun', '/ˈdɒktrɪn/', '教义；学说', 'a belief or set of beliefs held and taught by a church, a political party, or another group', '["The party''s doctrine emphasizes individual freedom.","Christian doctrine teaches the importance of forgiveness."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (135, 'en', 'domain', 'noun', '/dəˈmeɪn/', '领域；范围', 'an area of knowledge or activity; an area of land owned or controlled by a particular person', '["Artificial intelligence is a rapidly growing domain.","This problem falls within the domain of public health."]', 'B2', '["technology","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (136, 'en', 'dominant', 'adjective', '/ˈdɒmɪnənt/', '占主导地位的；显性的', 'more important, powerful, or noticeable than other things', '["The company has achieved a dominant position in the market.","English has become the dominant language of international business."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (137, 'en', 'donation', 'noun', '/dəʊˈneɪʃn/', '捐赠；捐款', 'something that is given to a person or an organization such as a charity, in order to help them', '["The charity relies on donations from the public.","She made a generous donation to the hospital."]', 'B2', '["society","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (138, 'en', 'draft', 'noun', '/drɑːft/', '草稿；草案', 'a rough written version of something that is not yet in its final form', '["She showed me the first draft of her essay.","The committee prepared a draft of the new regulations."]', 'B2', '["communication","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (139, 'en', 'dramatic', 'adjective', '/drəˈmætɪk/', '戏剧性的；引人注目的', 'sudden, very great, and often surprising; connected with the theatre or plays', '["There has been a dramatic increase in fuel prices.","The sunset over the mountains was quite dramatic."]', 'B2', '["arts","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (140, 'en', 'duration', 'noun', '/djʊˈreɪʃn/', '持续时间', 'the length of time that something lasts or continues', '["The duration of the flight is approximately six hours.","For the duration of the repairs, the road will be closed."]', 'B2', '["daily-life","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (141, 'en', 'echo', 'noun', '/ˈekəʊ/', '回声；共鸣', 'the reflecting of sound off a wall or inside an enclosed space so that it is heard again', '["She could hear the echo of her footsteps in the empty hall.","His words found an echo in the hearts of many people."]', 'B2', '["science","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (142, 'en', 'elaborate', 'adjective', '/ɪˈlæbərət/', '精心制作的；详尽的', 'very detailed and complicated; carefully prepared and organized', '["She wore an elaborate costume for the party.","He came up with an elaborate plan to surprise her."]', 'B2', '["arts","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (143, 'en', 'eligible', 'adjective', '/ˈelɪdʒəbl/', '有资格的；合格的', 'having the right qualifications or being in the right condition for something', '["Only students over 18 are eligible to vote.","She is eligible for a scholarship."]', 'B2', '["law","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (144, 'en', 'eliminate', 'verb', '/ɪˈlɪmɪneɪt/', '消除；淘汰', 'to remove or get rid of something completely', '["We need to eliminate all sources of infection.","Our team was eliminated in the first round of the competition."]', 'B2', '["science","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (145, 'en', 'embrace', 'verb', '/ɪmˈbreɪs/', '拥抱；欣然接受', 'to put your arms around somebody as a sign of love or friendship; to accept something enthusiastically', '["They embraced each other warmly at the airport.","The company has embraced new technology."]', 'B2', '["relationships","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (146, 'en', 'emerge', 'verb', '/ɪˈmɜːrdʒ/', '出现；浮现', 'to come out of a dark, confined, or hidden place; to start to exist or become known', '["The sun emerged from behind the clouds.","New evidence has emerged in the case."]', 'B2', '["daily-life","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (147, 'en', 'emission', 'noun', '/ɪˈmɪʃn/', '排放；排放物', 'the production or sending out of light, heat, gas, etc.', '["Carbon emissions from cars contribute to global warming.","The factory must reduce its emissions by 50%."]', 'B2', '["environment","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (148, 'en', 'emphasis', 'noun', '/ˈemfəsɪs/', '强调；重点', 'special importance that is given to something; extra force given to a word or phrase when speaking', '["The school places great emphasis on academic achievement.","He put special emphasis on the need for safety."]', 'B2', '["communication","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (149, 'en', 'encounter', 'verb', '/ɪnˈkaʊntər/', '遇到；遭遇', 'to experience something, especially something unpleasant or difficult; to meet somebody unexpectedly', '["We encountered several problems during the trip.","I first encountered his work at university."]', 'B2', '["daily-life","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (150, 'en', 'endure', 'verb', '/ɪnˈdjʊər/', '忍受；持续', 'to experience and deal with something that is painful or unpleasant without giving up', '["She endured years of pain before seeking help.","The friendship endured for over thirty years."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (151, 'en', 'enforce', 'verb', '/ɪnˈfɔːrs/', '执行；强制实施', 'to make sure that people obey a particular law or rule', '["The police are responsible for enforcing the law.","The new regulations will be strictly enforced."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (152, 'en', 'engagement', 'noun', '/ɪnˈɡeɪdʒmənt/', '订婚；参与', 'an agreement to marry; the act of being involved with something', '["They announced their engagement last month.","Student engagement is key to effective learning."]', 'B2', '["relationships","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (153, 'en', 'enhance', 'verb', '/ɪnˈhɑːns/', '增强；提高', 'to increase or further improve the good quality, value, or status of something', '["The new lighting enhances the beauty of the building.","Technology can enhance the learning experience."]', 'B2', '["technology","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (154, 'en', 'enterprise', 'noun', '/ˈentərpraɪz/', '企业；事业', 'a company or business; a large project, especially one that is difficult', '["The government supports small and medium enterprises.","Building the bridge was a massive engineering enterprise."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (155, 'en', 'entity', 'noun', '/ˈentəti/', '实体；存在', 'something that exists separately from other things and has its own identity', '["The company was set up as a separate legal entity.","The island became an independent political entity."]', 'B2', '["business","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (156, 'en', 'entrepreneur', 'noun', '/ˌɒntrəprəˈnɜːr/', '企业家；创业者', 'a person who makes money by starting or running businesses, especially when this involves taking financial risks', '["She became a successful entrepreneur at the age of 25.","The programme encourages young entrepreneurs to start their own businesses."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (157, 'en', 'epidemic', 'noun', '/ˌepɪˈdemɪk/', '流行病；蔓延', 'a large number of cases of a particular disease happening at the same time in a particular community', '["The flu epidemic affected thousands of people.","Obesity has reached epidemic proportions in some countries."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (158, 'en', 'erosion', 'noun', '/ɪˈrəʊʒn/', '侵蚀；腐蚀', 'the process by which the surface of something is gradually destroyed by the action of wind, rain, etc.', '["Soil erosion has become a serious environmental problem.","The erosion of civil liberties concerns many citizens."]', 'B2', '["environment","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (159, 'en', 'essence', 'noun', '/ˈesns/', '本质；精华', 'the most important quality or feature of something that makes it what it is', '["The essence of his argument is that we need more funding.","Time is of the essence in this matter."]', 'B2', '["education","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (160, 'en', 'ethnic', 'adjective', '/ˈeθnɪk/', '民族的；种族的', 'connected with or belonging to a nation, race, or people that shares a cultural tradition', '["The city has a rich ethnic diversity.","Ethnic minorities often face discrimination."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (161, 'en', 'evaluate', 'verb', '/ɪˈvæljueɪt/', '评估；评价', 'to form an opinion of the amount, value, or quality of something after thinking about it carefully', '["We need to evaluate the results of the experiment.","Teachers evaluate student progress throughout the year."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (162, 'en', 'evolution', 'noun', '/ˌiːvəˈluːʃn/', '进化；演变', 'the slow steady development of something; the process by which organisms develop over time', '["Darwin''s theory of evolution changed scientific thinking.","The evolution of technology has transformed modern life."]', 'B2', '["science","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (163, 'en', 'exaggerate', 'verb', '/ɪɡˈzædʒəreɪt/', '夸大；夸张', 'to make something seem larger, better, worse, or more important than it really is', '["He tends to exaggerate the dangers of the situation.","The importance of this discovery cannot be exaggerated."]', 'B2', '["communication","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (164, 'en', 'exceed', 'verb', '/ɪkˈsiːd/', '超过；超越', 'to be greater than a particular number or amount; to do more than the law or rules allow', '["The cost must not exceed fifty thousand dollars.","The results exceeded our expectations."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (165, 'en', 'exclusively', 'adverb', '/ɪkˈskluːsɪvli/', '专门地；排他地', 'only; for one particular person, group, or purpose and no others', '["The club is exclusively for members.","She works almost exclusively from home."]', 'B2', '["daily-life","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (166, 'en', 'exploit', 'verb', '/ɪkˈsplɔɪt/', '利用；剥削', 'to use something well in order to gain as much from it as possible; to treat somebody unfairly', '["We must exploit every opportunity that comes our way.","Workers were being exploited by their employers."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (167, 'en', 'exposure', 'noun', '/ɪkˈspəʊʒər/', '暴露；接触', 'the state of being in a place or situation where there is no protection; experience of something', '["Prolonged exposure to the sun can cause skin cancer.","The trip gave her exposure to different cultures."]', 'B2', '["health","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (168, 'en', 'extensive', 'adjective', '/ɪkˈstensɪv/', '广泛的；大量的', 'covering a large area; having a great range; large in amount or scale', '["The house has extensive gardens.","Extensive research has been carried out on this topic."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (169, 'en', 'extract', 'verb', '/ɪkˈstrækt/', '提取；摘录', 'to remove or obtain a substance from something, for example by using an industrial or chemical process', '["Oil is extracted from beneath the seabed.","The dentist had to extract two of her teeth."]', 'B2', '["science","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (170, 'en', 'fabric', 'noun', '/ˈfæbrɪk/', '织物；结构', 'material made by weaving wool, cotton, etc.; the basic structure of something', '["The dress is made from a lightweight cotton fabric.","Drugs threaten the very fabric of society."]', 'B2', '["daily-life","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (171, 'en', 'facilitate', 'verb', '/fəˈsɪlɪteɪt/', '促进；使便利', 'to make an action or a process possible or easier', '["The new software facilitates communication between departments.","Her role is to facilitate discussion among team members."]', 'B2', '["work","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (172, 'en', 'fatal', 'adjective', '/ˈfeɪtl/', '致命的；灾难性的', 'causing or ending in death; having very harmful results', '["The accident proved fatal for the driver.","Making that investment was a fatal mistake."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (173, 'en', 'fierce', 'adjective', '/fɪrs/', '猛烈的；激烈的', 'angry and aggressive in a way that is frightening; very strong or intense', '["There is fierce competition for places at the university.","The fierce wind knocked down several trees."]', 'B2', '["emotions","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (174, 'en', 'flourish', 'verb', '/ˈflʌrɪʃ/', '繁荣；茂盛', 'to develop quickly and be successful or common; to grow well', '["The arts flourished during the Renaissance.","Plants flourish in the warm, damp conditions."]', 'B2', '["environment","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (175, 'en', 'fluctuate', 'verb', '/ˈflʌktʃueɪt/', '波动；起伏', 'to change frequently in size, amount, quality, etc., especially from one extreme to another', '["Prices fluctuate according to demand.","Her mood fluctuated between hope and despair."]', 'B2', '["business","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (176, 'en', 'forecast', 'noun', '/ˈfɔːrkɑːst/', '预测；预报', 'a statement about what will happen in the future, based on information that is available now', '["The weather forecast predicts rain for tomorrow.","Economic forecasts suggest a period of slow growth."]', 'B2', '["environment","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (177, 'en', 'forge', 'verb', '/fɔːrdʒ/', '锻造；伪造', 'to make or produce something, especially with difficulty; to produce a copy of something illegally', '["The two countries forged a strong alliance.","He was arrested for forging documents."]', 'B2', '["relationships","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (178, 'en', 'formulate', 'verb', '/ˈfɔːrmjuleɪt/', '制定；构想', 'to create or prepare something carefully, giving particular attention to the details', '["The government is formulating a new policy on immigration.","It took time to formulate a response to the crisis."]', 'B2', '["politics","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (179, 'en', 'fossil', 'noun', '/ˈfɒsl/', '化石', 'the remains of an animal or a plant that have become hard and turned into rock', '["Fossils of dinosaurs have been found on every continent.","Fossil fuels such as coal and oil are non-renewable resources."]', 'B2', '["science","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (180, 'en', 'fraction', 'noun', '/ˈfrækʃn/', '分数；小部分', 'a small part or amount of something; a number that is not a whole number', '["Only a small fraction of the population voted.","She hesitated for a fraction of a second before answering."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (181, 'en', 'fragment', 'noun', '/ˈfræɡmənt/', '碎片；片段', 'a small part of something that has broken off or that comes from something larger', '["Fragments of glass were scattered across the floor.","I only heard fragments of their conversation."]', 'B2', '["daily-life","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (182, 'en', 'framework', 'noun', '/ˈfreɪmwɜːrk/', '框架；体系', 'a set of beliefs, ideas, or rules that is used as the basis for making judgements or decisions', '["The report provides a framework for future research.","We need to establish a legal framework for online commerce."]', 'B2', '["business","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (183, 'en', 'frustration', 'noun', '/frʌˈstreɪʃn/', '挫折；沮丧', 'the feeling of being annoyed or less confident because you cannot achieve what you want', '["He expressed his frustration at the lack of progress.","The delays caused widespread frustration among passengers."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (184, 'en', 'fulfil', 'verb', '/fʊlˈfɪl/', '实现；履行', 'to do or achieve what was hoped for or expected; to carry out a duty or promise', '["She finally fulfilled her dream of becoming a doctor.","The company failed to fulfil its contractual obligations."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (185, 'en', 'fundamental', 'adjective', '/ˌfʌndəˈmentl/', '基本的；根本的', 'serious and very important; affecting the most central and important parts of something', '["There is a fundamental difference between the two approaches.","Clean water is a fundamental human right."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (186, 'en', 'genuine', 'adjective', '/ˈdʒenjuɪn/', '真正的；真诚的', 'real; exactly what it appears to be; sincere and honest', '["Is the painting a genuine Rembrandt?","She showed genuine concern for his well-being."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (187, 'en', 'gesture', 'noun', '/ˈdʒestʃər/', '手势；姿态', 'a movement of part of the body, especially a hand or the head, to express an idea or meaning', '["He made a rude gesture at the other driver.","Sending flowers was a kind gesture."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (188, 'en', 'grasp', 'verb', '/ɡrɑːsp/', '抓住；理解', 'to take firm hold of something; to understand something completely', '["She grasped his hand tightly.","He failed to grasp the significance of the discovery."]', 'B2', '["education","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (189, 'en', 'guidance', 'noun', '/ˈɡaɪdns/', '指导；引导', 'help and advice about how to do something or about how to deal with problems', '["Children need guidance from their parents.","The teacher provided guidance on how to write the essay."]', 'B2', '["education","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (190, 'en', 'harsh', 'adjective', '/hɑːrʃ/', '严厉的；恶劣的', 'cruel, severe, and unkind; unpleasant and difficult to live in', '["The judge imposed a harsh sentence.","The harsh winter weather made travelling difficult."]', 'B2', '["law","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (191, 'en', 'heritage', 'noun', '/ˈherɪtɪdʒ/', '遗产；传统', 'the history, traditions, and qualities that a country or society has had for many years', '["The city is proud of its cultural heritage.","These buildings are part of our national heritage."]', 'B2', '["society","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (192, 'en', 'hierarchy', 'noun', '/ˈhaɪərɑːrki/', '等级制度；层级', 'a system in which people or things are arranged according to their importance', '["There is a strict hierarchy within the organization.","He quickly rose through the corporate hierarchy."]', 'B2', '["work","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (193, 'en', 'humanitarian', 'adjective', '/hjuːˌmænɪˈteəriən/', '人道主义的', 'concerned with reducing suffering and improving the conditions that people live in', '["The organization provides humanitarian aid to refugees.","The country is facing a humanitarian crisis."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (194, 'en', 'hypothesis', 'noun', '/haɪˈpɒθəsɪs/', '假说；假设', 'an idea or explanation of something that is based on a few known facts but that has not yet been proved to be true', '["The scientist put forward a hypothesis to explain the results.","We need to test this hypothesis with further experiments."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (195, 'en', 'ideology', 'noun', '/ˌaɪdiˈɒlədʒi/', '意识形态；思想体系', 'a set of beliefs, especially one held by a particular group, that influences the way people behave', '["Political ideology shapes government policy.","The two countries are divided by ideology."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (196, 'en', 'ignorance', 'noun', '/ˈɪɡnərəns/', '无知；愚昧', 'a lack of knowledge or information about something', '["His ignorance of the law is no excuse.","Public ignorance about the disease needs to be addressed."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (197, 'en', 'illustrate', 'verb', '/ˈɪləstreɪt/', '说明；图解', 'to make the meaning of something clearer by using examples, pictures, etc.', '["The report illustrates the need for more investment.","The book is beautifully illustrated with colour photographs."]', 'B2', '["education","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (198, 'en', 'immense', 'adjective', '/ɪˈmens/', '巨大的；无限的', 'extremely large or great', '["The task requires an immense amount of patience.","She felt immense relief when the results were announced."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (199, 'en', 'imperial', 'adjective', '/ɪmˈpɪəriəl/', '帝国的；皇帝的', 'connected with an empire; connected with the system for measuring length, weight, etc. using pounds, inches, etc.', '["The imperial palace was built in the 15th century.","Britain converted from the imperial system to the metric system."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (200, 'en', 'implement', 'verb', '/ˈɪmplɪment/', '实施；执行', 'to make something that has been officially decided start to happen or be used', '["The government has failed to implement the reforms.","The new system will be implemented next year."]', 'B2', '["work","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (201, 'en', 'impose', 'verb', '/ɪmˈpəʊz/', '强制推行；把……强加于', 'to introduce a new law, rule, tax, etc. and force people to accept it', '["The government imposed a ban on smoking in public places.","I don''t want to impose my views on anyone."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (202, 'en', 'impress', 'verb', '/ɪmˈpres/', '给……留下深刻印象；使钦佩', 'to make someone feel admiration and respect', '["She dressed smartly to impress at the job interview.","His cooking skills really impressed the dinner guests."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (203, 'en', 'impulse', 'noun', '/ˈɪmpʌls/', '冲动；一时兴起', 'a sudden strong desire to do something without thinking about the results', '["I bought the jacket on impulse and regretted it later.","She had a sudden impulse to call her old friend."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (204, 'en', 'incidence', 'noun', '/ˈɪnsɪdəns/', '发生率；影响范围', 'the extent to which something happens or has an effect', '["There is a high incidence of flu during winter months.","The incidence of food allergies has increased in recent years."]', 'B2', '["science","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (205, 'en', 'incline', 'verb', '/ɪnˈklaɪn/', '倾向于；使倾斜', 'to tend to think or behave in a particular way', '["I incline towards the vegetarian option when eating out.","He''s inclined to stay home rather than go to parties."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (206, 'en', 'incorporate', 'verb', '/ɪnˈkɔːpəreɪt/', '包含；合并；纳入', 'to include something as part of a group, system, or plan', '["The new menu incorporates dishes from several countries.","Try to incorporate more vegetables into your daily meals."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (207, 'en', 'incredible', 'adjective', '/ɪnˈkredəbl/', '难以置信的；极好的', 'impossible or very difficult to believe; extremely good', '["The view from the mountain top was absolutely incredible.","It''s incredible how fast children grow up."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (208, 'en', 'indicator', 'noun', '/ˈɪndɪkeɪtə(r)/', '指示物；指标', 'a sign that shows you what something is like or how a situation is changing', '["Dark clouds are a good indicator of coming rain.","Your energy level is an indicator of your overall health."]', 'B2', '["science","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (209, 'en', 'indigenous', 'adjective', '/ɪnˈdɪdʒənəs/', '本土的；当地的', 'belonging to a particular place rather than coming from somewhere else', '["We visited a market selling indigenous crafts and foods.","Many indigenous plants in this region are used in traditional cooking."]', 'B2', '["society","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (210, 'en', 'induce', 'verb', '/ɪnˈdjuːs/', '引起；诱使；导致', 'to cause something to happen or to persuade someone to do something', '["Too much coffee can induce anxiety and sleeplessness.","Nothing could induce me to go bungee jumping."]', 'B2', '["health","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (211, 'en', 'inevitable', 'adjective', '/ɪnˈevɪtəbl/', '不可避免的；必然发生的', 'certain to happen and impossible to avoid or prevent', '["Traffic jams are inevitable during the holiday season.","It was inevitable that the old shop would eventually close."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (212, 'en', 'infant', 'noun', '/ˈɪnfənt/', '婴儿；幼儿', 'a baby or very young child', '["The store has a special section for infant clothing.","Infants need to be fed every few hours."]', 'B2', '["health","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (213, 'en', 'inflict', 'verb', '/ɪnˈflɪkt/', '使遭受（损伤、痛苦等）', 'to make someone or something suffer something unpleasant', '["The storm inflicted serious damage on the coastal town.","I didn''t mean to inflict so much stress on my family by moving abroad."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (214, 'en', 'influential', 'adjective', '/ˌɪnfluˈenʃl/', '有影响力的；有权势的', 'having a lot of influence on someone or something', '["She follows several influential food bloggers on social media.","He became one of the most influential teachers at the school."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (215, 'en', 'infrastructure', 'noun', '/ˈɪnfrəstrʌktʃə(r)/', '基础设施；基础建设', 'the basic systems and services that a country or organization needs in order to work properly', '["The city invested heavily in transport infrastructure like roads and bridges.","Poor internet infrastructure makes working from home difficult in rural areas."]', 'B2', '["politics","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (216, 'en', 'inhabit', 'verb', '/ɪnˈhæbɪt/', '居住于；栖息于', 'to live in a particular place', '["Several rare bird species inhabit the wetlands near our village.","The island has been inhabited for thousands of years."]', 'B2', '["environment","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (217, 'en', 'inherent', 'adjective', '/ɪnˈhɪərənt/', '固有的；内在的', 'existing as a natural or basic part of something', '["There is an inherent risk in any outdoor adventure sport.","Creativity is an inherent part of cooking without a recipe."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (218, 'en', 'inherit', 'verb', '/ɪnˈherɪt/', '继承；经遗传获得', 'to receive money, property, or a title from someone who has died; to have qualities that a parent or relative has', '["She inherited her grandmother''s love of gardening.","He inherited the family house when his father passed away."]', 'B2', '["law","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (219, 'en', 'inject', 'verb', '/ɪnˈdʒekt/', '注射；注入', 'to put a drug or substance into the body using a needle; to add a quality to something', '["The nurse injected the vaccine into my arm.","We need to inject some fun into this boring weekend."]', 'B2', '["health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (220, 'en', 'innovation', 'noun', '/ˌɪnəˈveɪʃn/', '创新；新方法', 'a new idea, method, or invention', '["Smartphone technology has been one of the biggest innovations of our time.","The restaurant is known for its innovation in plant-based cooking."]', 'B2', '["technology","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (221, 'en', 'input', 'noun', '/ˈɪnpʊt/', '输入；投入；意见', 'ideas, advice, effort, or information that is put into something', '["We value your input on how to improve our service.","The project benefited from input from team members of all ages."]', 'B2', '["work","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (222, 'en', 'inquiry', 'noun', '/ɪnˈkwaɪəri/', '询问；调查', 'a request for information; an official investigation', '["I made an inquiry about flight prices for the summer holiday.","The shop received several inquiries about the new product."]', 'B2', '["communication","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (223, 'en', 'inspect', 'verb', '/ɪnˈspekt/', '检查；审视', 'to look at something carefully to check that it is correct or in good condition', '["Always inspect fruit carefully before buying it at the market.","The landlord came to inspect the flat before we moved out."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (224, 'en', 'inspire', 'verb', '/ɪnˈspaɪə(r)/', '激励；启发；赋予灵感', 'to give someone the desire, confidence, or enthusiasm to do something', '["Her travel stories inspired me to book my own trip abroad.","The cooking show inspired him to try making pasta from scratch."]', 'B2', '["emotions","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (225, 'en', 'installment', 'noun', '/ɪnˈstɔːlmənt/', '分期付款；（连载的）一期', 'one of a number of payments that are made regularly over a period of time until something has been paid for', '["We paid for the sofa in six monthly installments.","The final installment of the TV series airs next week."]', 'B2', '["business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (226, 'en', 'instance', 'noun', '/ˈɪnstəns/', '实例；情况', 'a particular example or case of something', '["There have been several instances of food poisoning at that restaurant.","In this instance, I think it''s better to wait before making a decision."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (227, 'en', 'instinct', 'noun', '/ˈɪnstɪŋkt/', '本能；直觉', 'a natural tendency to behave in a particular way without having to learn it or think about it', '["My first instinct was to check if everyone was okay after the accident.","Trust your instincts when something doesn''t feel right."]', 'B2', '["emotions","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (228, 'en', 'intact', 'adjective', '/ɪnˈtækt/', '完好无损的；完整的', 'complete and not damaged', '["Luckily, the package arrived with everything intact.","The old castle remains mostly intact after hundreds of years."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (229, 'en', 'integrate', 'verb', '/ˈɪntɪɡreɪt/', '整合；融入', 'to combine two or more things so that they work together; to become part of a group', '["It took a while to integrate into the new neighbourhood after moving.","The school tries to integrate technology into everyday learning."]', 'B2', '["society","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (230, 'en', 'integrity', 'noun', '/ɪnˈteɡrəti/', '正直；诚实；完整性', 'the quality of being honest and having strong moral principles', '["She is known for her integrity and always keeps her promises.","The integrity of the old building was tested by the earthquake."]', 'B2', '["emotions","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (231, 'en', 'intellectual', 'adjective', '/ˌɪntəˈlektʃuəl/', '智力的；知识分子的', 'connected with or using a person''s ability to think in a logical way and understand things', '["Reading is a great way to get intellectual stimulation.","They enjoyed intellectual conversations over coffee."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (232, 'en', 'intense', 'adjective', '/ɪnˈtens/', '强烈的；紧张的；激烈的', 'very great or extreme in strength or degree', '["The intense heat during the summer made it hard to sleep.","She felt intense pressure before the final exam."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (233, 'en', 'interact', 'verb', '/ˌɪntərˈækt/', '互动；交流', 'to communicate or react with each other', '["Children learn social skills by interacting with other kids at school.","The app allows customers to interact directly with the shop owner."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (234, 'en', 'interfere', 'verb', '/ˌɪntəˈfɪə(r)/', '干涉；妨碍', 'to get involved in a situation that does not concern you; to prevent something from working properly', '["Please don''t interfere with my plans for the weekend.","The loud music from next door interfered with my studying."]', 'B2', '["relationships","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (235, 'en', 'interior', 'noun', '/ɪnˈtɪəriə(r)/', '内部；室内', 'the inside part of something, especially a building or vehicle', '["The interior of the café was decorated in a cosy vintage style.","She hired a designer to redo the interior of her apartment."]', 'B2', '["daily-life","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (236, 'en', 'intermediate', 'adjective', '/ˌɪntəˈmiːdiət/', '中级的；中间的', 'between two stages, levels, or positions', '["She signed up for an intermediate yoga class.","This textbook is designed for intermediate-level English learners."]', 'B2', '["education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (237, 'en', 'interpret', 'verb', '/ɪnˈtɜːprɪt/', '解释；口译；理解', 'to explain or decide the meaning of something; to translate spoken words from one language to another', '["She interpreted his silence as disagreement.","A guide interpreted for us during our trip to Japan."]', 'B2', '["communication","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (238, 'en', 'intervene', 'verb', '/ˌɪntəˈviːn/', '干预；介入；调停', 'to become involved in a situation in order to improve or help it', '["A neighbour intervened when they heard the argument getting louder.","The teacher had to intervene to stop the children from fighting."]', 'B2', '["relationships","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (239, 'en', 'intimate', 'adjective', '/ˈɪntɪmət/', '亲密的；私密的', 'having a close and personal relationship; private and personal', '["They had an intimate dinner for two at a quiet restaurant.","She shared intimate details about her childhood with her best friend."]', 'B2', '["relationships","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (240, 'en', 'invade', 'verb', '/ɪnˈveɪd/', '入侵；侵犯', 'to enter a place in large numbers, especially in order to take control; to affect something in an unwanted way', '["Ants invaded the kitchen after we left food on the counter.","Tourists invade the small coastal town every summer."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (241, 'en', 'invisible', 'adjective', '/ɪnˈvɪzəbl/', '看不见的；无形的', 'impossible to see', '["The stain was almost invisible after she cleaned the shirt.","He felt invisible at the party because nobody talked to him."]', 'B2', '["daily-life","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (242, 'en', 'isolation', 'noun', '/ˌaɪsəˈleɪʃn/', '隔离；孤立', 'the state of being separate from other people or things', '["Working from home can sometimes lead to feelings of isolation.","The village''s isolation made it difficult to get fresh supplies."]', 'B2', '["emotions","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (243, 'en', 'journal', 'noun', '/ˈdʒɜːnl/', '日记；期刊；杂志', 'a written record of what you do each day; a newspaper or magazine that deals with a particular subject', '["She keeps a journal to write down her thoughts before bed.","He published his research in an international science journal."]', 'B2', '["communication","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (244, 'en', 'judicial', 'adjective', '/dʒuˈdɪʃl/', '司法的；审判的', 'connected with a court of law, a judge, or a legal judgement', '["The judicial system is supposed to treat everyone equally.","A judicial review was ordered to examine the decision."]', 'B2', '["law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (245, 'en', 'keen', 'adjective', '/kiːn/', '热衷的；渴望的；敏锐的', 'very interested in or enthusiastic about something', '["She''s a keen gardener and spends every weekend in her garden.","He''s keen to learn how to cook Italian food."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (246, 'en', 'landscape', 'noun', '/ˈlændskeɪp/', '风景；景色；地形', 'everything you can see when you look across a large area of land', '["The train journey offered stunning views of the countryside landscape.","The landscape changes dramatically as you drive from the coast to the mountains."]', 'B2', '["environment","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (247, 'en', 'lately', 'adverb', '/ˈleɪtli/', '最近；近来', 'recently; in the recent past', '["I''ve been feeling really tired lately.","Have you seen any good films lately?"]', 'B2', '["daily-life","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (248, 'en', 'latter', 'adjective', '/ˈlætə(r)/', '后者的；后半的', 'being the second of two things or people that have just been mentioned', '["Between tea and coffee, I prefer the latter.","The latter half of the trip was much more enjoyable."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (249, 'en', 'launch', 'verb', '/lɔːntʃ/', '发起；推出；发射', 'to start something new or make a new product available for the first time', '["The company launched a new range of organic snacks.","She launched her own online clothing store last year."]', 'B2', '["business","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (250, 'en', 'leap', 'verb', '/liːp/', '跳跃；猛增；迅速行动', 'to jump high or a long way; to increase suddenly by a large amount', '["The cat leapt onto the kitchen counter to steal some fish.","House prices leapt by 10% in just one year."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (251, 'en', 'legitimate', 'adjective', '/lɪˈdʒɪtɪmət/', '合法的；正当的；合理的', 'allowed by law; fair or reasonable', '["Make sure you buy from a legitimate online seller.","He had a legitimate reason for arriving late to work."]', 'B2', '["law","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (252, 'en', 'leisure', 'noun', '/ˈleʒə(r)/', '空闲；休闲时间', 'time when you are not working or studying and can relax and do things you enjoy', '["I like to spend my leisure time reading or going for walks.","The hotel has a pool and other leisure facilities."]', 'B2', '["daily-life","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (253, 'en', 'liable', 'adjective', '/ˈlaɪəbl/', '有责任的；很可能的', 'legally responsible for something; likely to do something', '["The shop is not liable for items left in the changing room.","You''re liable to catch a cold if you go out without a jacket."]', 'B2', '["law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (254, 'en', 'liberal', 'adjective', '/ˈlɪbərəl/', '开明的；慷慨的；自由主义的', 'willing to accept different opinions and ways of behaving; generous', '["She has very liberal views on education and parenting.","He was liberal with his compliments at the dinner party."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (255, 'en', 'likewise', 'adverb', '/ˈlaɪkwaɪz/', '同样地；也', 'in the same way; also', '["\"It was lovely meeting you.\" \"Likewise!\"","He grabbed a coffee, and I did likewise."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (256, 'en', 'limb', 'noun', '/lɪm/', '肢体；（树的）大枝', 'an arm or leg of a person or animal; a large branch of a tree', '["He stretched his tired limbs after the long flight.","The storm broke several large limbs off the old oak tree."]', 'B2', '["health","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (257, 'en', 'linear', 'adjective', '/ˈlɪniə(r)/', '线性的；直线的', 'going from one thing to another in a single direction or series of stages', '["Career paths are rarely linear — most people change direction several times.","The story is told in a linear fashion, from beginning to end."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (258, 'en', 'linger', 'verb', '/ˈlɪŋɡə(r)/', '逗留；徘徊；持续', 'to stay somewhere for longer than expected; to continue to exist for longer than expected', '["We lingered over coffee at the café, chatting for hours.","The smell of freshly baked bread lingered in the kitchen all morning."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (259, 'en', 'literacy', 'noun', '/ˈlɪtərəsi/', '读写能力；素养', 'the ability to read and write; knowledge of a particular subject', '["The charity works to improve literacy rates among children.","Financial literacy is an important skill for managing your money."]', 'B2', '["education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (260, 'en', 'literally', 'adverb', '/ˈlɪtərəli/', '字面上地；确实地', 'in the most basic or original meaning of a word or expression; used to emphasize something', '["The town was literally flooded — water covered all the streets.","I literally just walked through the door when the phone rang."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (261, 'en', 'logical', 'adjective', '/ˈlɒdʒɪkl/', '合乎逻辑的；合理的', 'seeming natural, reasonable, or sensible', '["It seemed logical to take the shorter route to avoid traffic.","There must be a logical explanation for why the door was open."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (262, 'en', 'lone', 'adjective', '/ləʊn/', '单独的；孤零零的', 'without any other people or things; single', '["A lone jogger was running along the beach at sunrise.","She was the lone vegetarian at the barbecue."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (263, 'en', 'long-term', 'adjective', '/ˌlɒŋ ˈtɜːm/', '长期的', 'continuing for a long period of time into the future', '["We need a long-term plan for saving enough to buy a house.","Regular exercise has long-term benefits for your health."]', 'B2', '["business","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (264, 'en', 'loyalty', 'noun', '/ˈlɔɪəlti/', '忠诚；忠实', 'the quality of being faithful in your support of someone or something', '["Customer loyalty is rewarded with a 10% discount card.","His loyalty to his friends has never been questioned."]', 'B2', '["relationships","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (265, 'en', 'magnitude', 'noun', '/ˈmæɡnɪtjuːd/', '巨大；重要性；规模', 'the great size or importance of something', '["I didn''t fully understand the magnitude of the problem until it was too late.","An earthquake of that magnitude can cause serious damage."]', 'B2', '["science","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (266, 'en', 'mainstream', 'adjective', '/ˈmeɪnstriːm/', '主流的', 'considered normal because it is shared by most people in a society', '["Veganism has become much more mainstream in recent years.","The band started as an indie group but soon entered the mainstream music scene."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (267, 'en', 'manifest', 'verb', '/ˈmænɪfest/', '表明；显现', 'to show something clearly, especially a feeling or quality', '["Her nervousness manifested itself as a slight trembling in her hands.","Stress can manifest in many different physical symptoms."]', 'B2', '["emotions","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (268, 'en', 'manipulate', 'verb', '/məˈnɪpjuleɪt/', '操纵；控制；操作', 'to control or influence someone or something in a clever or dishonest way', '["He tried to manipulate his colleagues into doing his share of the work.","The software allows you to manipulate images easily."]', 'B2', '["relationships","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (269, 'en', 'marginal', 'adjective', '/ˈmɑːdʒɪnl/', '边缘的；微小的；不重要的', 'small and not important; not part of the main group', '["There was only a marginal improvement in sales this quarter.","The difference in taste between the two brands is marginal."]', 'B2', '["business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (270, 'en', 'mature', 'adjective', '/məˈtʃʊə(r)/', '成熟的；成年的', 'behaving in a sensible way, like an adult; fully grown or developed', '["She''s very mature for her age and handles problems calmly.","This cheese is left to mature for at least twelve months."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (271, 'en', 'maximize', 'verb', '/ˈmæksɪmaɪz/', '使最大化；充分利用', 'to increase something as much as possible', '["Arrange the furniture carefully to maximize the space in a small flat.","She tried to maximize her holiday time by booking flights at the best times."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (272, 'en', 'mechanism', 'noun', '/ˈmekənɪzəm/', '机制；机械装置；方法', 'a set of moving parts in a machine; a method or system for achieving something', '["The lock mechanism on the front door is broken.","Exercise is a great mechanism for dealing with stress."]', 'B2', '["science","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (273, 'en', 'medieval', 'adjective', '/ˌmediˈiːvl/', '中世纪的', 'connected with the Middle Ages (about AD 600 to AD 1500)', '["We visited a beautiful medieval castle during our trip to Spain.","The town centre still has its medieval walls and narrow streets."]', 'B2', '["society","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (274, 'en', 'merely', 'adverb', '/ˈmɪəli/', '仅仅；只不过', 'used to emphasize that something is small, unimportant, or not enough', '["I''m not criticizing — I''m merely making a suggestion.","She''s merely a beginner, so don''t expect perfect results."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (275, 'en', 'merit', 'noun', '/ˈmerɪt/', '优点；价值；功绩', 'the quality of being good or worthy of praise; an advantage', '["Each application will be judged on its own merits.","One of the merits of living in the countryside is the fresh air."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (276, 'en', 'mere', 'adjective', '/mɪə(r)/', '仅仅的；只不过的', 'used to emphasize how small or unimportant something is', '["The mere thought of public speaking makes her nervous.","He''s a mere child — you can''t expect him to understand."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (277, 'en', 'migrate', 'verb', '/maɪˈɡreɪt/', '迁移；移居', 'to move from one place to another, especially to find work or better living conditions', '["Many birds migrate south during the winter months.","His grandparents migrated to Australia in search of a better life."]', 'B2', '["environment","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (278, 'en', 'mild', 'adjective', '/maɪld/', '温和的；轻微的', 'not severe or strong; gentle', '["We had a mild winter this year with very little snow.","The curry was too mild for my taste — I prefer spicy food."]', 'B2', '["environment","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (279, 'en', 'minimize', 'verb', '/ˈmɪnɪmaɪz/', '使减到最少；最小化', 'to reduce something to the smallest possible level or amount', '["Wearing sunscreen helps minimize the risk of sunburn.","We rearranged the schedule to minimize waiting time for customers."]', 'B2', '["business","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (280, 'en', 'ministry', 'noun', '/ˈmɪnɪstri/', '（政府的）部；部门', 'a government department that has a particular area of responsibility', '["The Ministry of Education announced changes to the school curriculum.","She works at the ministry dealing with environmental protection."]', 'B2', '["politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (281, 'en', 'minor', 'adjective', '/ˈmaɪnə(r)/', '较小的；次要的；轻微的', 'not very large, important, or serious', '["It was only a minor injury — just a small cut on his finger.","There are a few minor changes I''d like to make to the travel plan."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (282, 'en', 'mobility', 'noun', '/məʊˈbɪləti/', '流动性；移动能力', 'the ability to move or travel easily from one place, job, or social class to another', '["A good public transport system improves mobility for everyone.","Yoga helps improve your flexibility and mobility as you age."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (283, 'en', 'moderate', 'adjective', '/ˈmɒdərət/', '适度的；中等的；温和的', 'average in amount, intensity, or degree; not extreme', '["Doctors recommend moderate exercise, like a 30-minute daily walk.","The hotel was clean and comfortable at a moderate price."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (284, 'en', 'modify', 'verb', '/ˈmɒdɪfaɪ/', '修改；调整；缓和', 'to change something slightly, especially to improve it or make it less extreme', '["I modified the recipe to make it dairy-free.","You can modify the workout to suit your fitness level."]', 'B2', '["technology","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (285, 'en', 'monopoly', 'noun', '/məˈnɒpəli/', '垄断；专卖权', 'complete control of trade in particular goods or of the supply of a particular service', '["The company had a monopoly on internet services in the area.","No single supermarket should have a monopoly over food prices."]', 'B2', '["business","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (286, 'en', 'moreover', 'adverb', '/mɔːrˈəʊvə(r)/', '而且；此外', 'used to introduce an extra piece of information that supports what has already been said', '["The restaurant is affordable; moreover, the food is excellent.","He''s hardworking and, moreover, always willing to help others."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (287, 'en', 'mortgage', 'noun', '/ˈmɔːɡɪdʒ/', '抵押贷款；按揭', 'a legal agreement by which a bank lends you money to buy a house, and you pay the money back over a period of years', '["They took out a 25-year mortgage to buy their first home.","Paying the mortgage is our biggest monthly expense."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (288, 'en', 'motive', 'noun', '/ˈməʊtɪv/', '动机；目的', 'a reason for doing something', '["His main motive for changing jobs was to spend more time with his family.","What was the motive behind her sudden decision to move abroad?"]', 'B2', '["emotions","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (289, 'en', 'mutual', 'adjective', '/ˈmjuːtʃuəl/', '相互的；共同的', 'felt or done equally by two or more people towards each other', '["They became friends through a mutual love of hiking.","The decision to break up was mutual — they both agreed."]', 'B2', '["relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (290, 'en', 'namely', 'adverb', '/ˈneɪmli/', '即；也就是', 'used to introduce more exact or detailed information about something', '["There''s one thing I really miss about home, namely my mum''s cooking.","Two students passed with top marks, namely Sarah and Tom."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (291, 'en', 'navigate', 'verb', '/ˈnævɪɡeɪt/', '导航；浏览；应对', 'to find the right way to deal with a difficult situation; to find your way', '["It can be hard to navigate a new city without a map app.","She helped me navigate the complicated visa application process."]', 'B2', '["travel","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (292, 'en', 'nearby', 'adverb', '/ˌnɪəˈbaɪ/', '在附近', 'not far away; close', '["Is there a pharmacy nearby? I need to buy some medicine.","We parked the car and walked to a nearby restaurant for lunch."]', 'B2', '["travel","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (293, 'en', 'neglect', 'verb', '/nɪˈɡlekt/', '忽视；疏忽', 'to fail to take care of or give enough attention to someone or something', '["Don''t neglect your health just because you''re busy with work.","The garden had been neglected for years and was full of weeds."]', 'B2', '["relationships","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (294, 'en', 'negotiate', 'verb', '/nɪˈɡəʊʃieɪt/', '谈判；协商', 'to try to reach an agreement by formal discussion', '["She negotiated a better price for the car before buying it.","The two sides are still negotiating the terms of the contract."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (295, 'en', 'nonetheless', 'adverb', '/ˌnʌnðəˈles/', '尽管如此；然而', 'despite what has just been said; nevertheless', '["The weather was terrible; nonetheless, we enjoyed the trip.","It''s a small restaurant but nonetheless very popular with locals."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (296, 'en', 'norm', 'noun', '/nɔːm/', '规范；准则；常态', 'a standard or pattern of behaviour that is typical or expected', '["Working from home has become the norm for many people.","Social norms vary greatly from one culture to another."]', 'B2', '["society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (297, 'en', 'notable', 'adjective', '/ˈnəʊtəbl/', '值得注意的；显著的', 'important, interesting, or deserving attention', '["There has been a notable increase in the number of cyclists in the city.","The most notable feature of the hotel was its rooftop swimming pool."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (298, 'en', 'notwithstanding', 'preposition', '/ˌnɒtwɪθˈstændɪŋ/', '尽管；虽然', 'despite something; without being affected by something', '["Notwithstanding the rain, we decided to go ahead with the picnic.","The team won the match, notwithstanding the loss of their best player."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (299, 'en', 'nurture', 'verb', '/ˈnɜːtʃə(r)/', '培育；养育；培养', 'to care for and encourage the growth or development of someone or something', '["Parents play a key role in nurturing their children''s confidence.","She nurtured her love of painting from a young age into a career."]', 'B2', '["relationships","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (300, 'en', 'oblige', 'verb', '/əˈblaɪdʒ/', '迫使；使感激；帮忙', 'to force someone to do something; to do something that someone has asked you to do', '["The new law obliges restaurants to display calorie counts on menus.","I asked if she could swap shifts with me, and she kindly obliged."]', 'B2', '["law","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (301, 'en', 'narrative', 'noun', '/ˈnærətɪv/', '叙述；故事', 'a description of events, especially in a novel or story', '["The movie has a compelling narrative that keeps you watching.","She gave a detailed narrative of her trip to Japan."]', 'B2', '["arts","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (302, 'en', 'nevertheless', 'adverb', '/ˌnevərðəˈles/', '然而；不过', 'despite something that you have just mentioned', '["The weather was terrible. Nevertheless, we had a great time.","It''s a difficult exam; nevertheless, I think you should try."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (303, 'en', 'noble', 'adjective', '/ˈnoʊbl/', '高尚的；高贵的', 'having fine personal qualities that people admire, such as courage and honesty', '["It was noble of him to volunteer at the shelter every weekend.","She comes from a noble family with a long history."]', 'B2', '["society","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (304, 'en', 'nominate', 'verb', '/ˈnɑːmɪneɪt/', '提名；任命', 'to formally suggest somebody for a job, a prize, or an election', '["She was nominated for the best employee award this year.","The committee nominated him as the new chairperson."]', 'B2', '["work","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (305, 'en', 'notably', 'adverb', '/ˈnoʊtəbli/', '尤其；显著地', 'used to draw attention to something important or to a particular example', '["Several people helped, notably my neighbour who cooked meals for us.","The city has changed notably in the last ten years."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (306, 'en', 'notify', 'verb', '/ˈnoʊtɪfaɪ/', '通知；告知', 'to formally or officially tell somebody about something', '["Please notify us if you change your address.","The school notified parents about the schedule change."]', 'B2', '["communication","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (307, 'en', 'notorious', 'adjective', '/noʊˈtɔːriəs/', '臭名昭著的；声名狼藉的', 'well known for being bad or unpleasant', '["That road is notorious for traffic jams during rush hour.","He''s notorious for arriving late to every meeting."]', 'B2', '["society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (308, 'en', 'novel', 'adjective', '/ˈnɑːvl/', '新颖的；新奇的', 'different from anything known before; new, interesting, and often seeming slightly strange', '["She came up with a novel way to organize her wardrobe.","That''s a novel approach to solving the parking problem."]', 'B2', '["technology","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (309, 'en', 'numerous', 'adjective', '/ˈnuːmərəs/', '许多的；众多的', 'existing in large numbers', '["I''ve been to that café on numerous occasions.","Numerous studies show that exercise improves mental health."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (310, 'en', 'objection', 'noun', '/əbˈdʒekʃn/', '反对；异议', 'a reason why you disagree with or disapprove of something', '["Does anyone have any objections to the new plan?","She raised an objection to the idea of working on weekends."]', 'B2', '["communication","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (311, 'en', 'obligation', 'noun', '/ˌɑːblɪˈɡeɪʃn/', '义务；责任', 'something that you must do because of a law, rule, or promise', '["You have no obligation to buy anything after the free trial.","Parents have an obligation to look after their children."]', 'B2', '["law","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (312, 'en', 'obscure', 'adjective', '/əbˈskjʊr/', '模糊的；鲜为人知的', 'not well known; difficult to understand', '["He enjoys watching obscure foreign films that nobody has heard of.","The instructions were so obscure that no one could follow them."]', 'B2', '["arts","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (313, 'en', 'obsess', 'verb', '/əbˈses/', '使着迷；使困扰', 'to think about something or somebody too much and in a way that is not normal', '["She tends to obsess over every small detail before a presentation.","Don''t obsess about your weight — focus on being healthy."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (314, 'en', 'obstacle', 'noun', '/ˈɑːbstəkl/', '障碍；阻碍', 'something that makes it difficult for you to do something or go somewhere', '["Lack of funding is the biggest obstacle to our project.","She overcame many obstacles to become a successful chef."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (315, 'en', 'obtain', 'verb', '/əbˈteɪn/', '获得；得到', 'to get something, especially by making an effort', '["You can obtain a visa at the embassy.","She obtained her driving licence on the first attempt."]', 'B2', '["daily-life","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (316, 'en', 'occupy', 'verb', '/ˈɑːkjupaɪ/', '占据；使忙碌', 'to fill or use a space, area, or amount of time', '["Books and photos occupy most of the shelf space in my room.","Cooking and cleaning occupy a lot of my time on weekends."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (317, 'en', 'odds', 'noun', '/ɑːdz/', '可能性；几率', 'the degree to which something is likely to happen', '["The odds of winning the lottery are extremely low.","Against all odds, he recovered fully from the injury."]', 'B2', '["daily-life","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (318, 'en', 'offend', 'verb', '/əˈfend/', '冒犯；使不快', 'to make somebody feel upset or annoyed because of something you say or do', '["I''m sorry if my comment offended you — it wasn''t intentional.","She was offended when he forgot her birthday."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (319, 'en', 'ongoing', 'adjective', '/ˈɑːnɡoʊɪŋ/', '持续的；进行中的', 'continuing to exist or develop', '["The renovation is an ongoing project that should finish by summer.","There''s an ongoing debate about whether to change the school uniform."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (320, 'en', 'optional', 'adjective', '/ˈɑːpʃənl/', '可选的；非必须的', 'that you can choose to do or have if you want to', '["The guided tour is optional — you can explore on your own.","Wearing a tie to the office is optional on Fridays."]', 'B2', '["education","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (321, 'en', 'originate', 'verb', '/əˈrɪdʒɪneɪt/', '起源于；发源于', 'to happen or appear for the first time in a particular place or situation', '["The tradition of afternoon tea originated in England.","The idea for the app originated from a conversation with friends."]', 'B2', '["society","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (322, 'en', 'otherwise', 'adverb', '/ˈʌðərwaɪz/', '否则；除此以外', 'used to state what the result would be if something did not happen', '["You should leave now, otherwise you''ll miss the train.","The food was a bit cold, but otherwise the dinner was lovely."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (323, 'en', 'outbreak', 'noun', '/ˈaʊtbreɪk/', '爆发；突然发生', 'the sudden start of something unpleasant, especially a disease or violence', '["There was an outbreak of food poisoning at the school cafeteria.","The outbreak of flu kept many workers at home last winter."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (324, 'en', 'outcome', 'noun', '/ˈaʊtkʌm/', '结果；后果', 'the result or effect of an action or event', '["We''re still waiting for the outcome of the job interview.","The outcome of the match surprised everyone."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (325, 'en', 'outline', 'verb', '/ˈaʊtlaɪn/', '概述；描述要点', 'to give the main facts or ideas about something', '["She outlined her plans for redecorating the living room.","The teacher outlined what topics the exam would cover."]', 'B2', '["communication","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (326, 'en', 'outlook', 'noun', '/ˈaʊtlʊk/', '观点；前景', 'your attitude to life and the world; the likely future situation', '["She has a very positive outlook on life despite the challenges.","The economic outlook for next year looks promising."]', 'B2', '["emotions","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (327, 'en', 'output', 'noun', '/ˈaʊtpʊt/', '产量；输出', 'the amount of something that a person, machine, or organization produces', '["The factory has increased its output by 20% this year.","She was praised for her creative output during the project."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (328, 'en', 'outrage', 'noun', '/ˈaʊtreɪdʒ/', '愤怒；暴行', 'a strong feeling of shock and anger', '["There was public outrage over the increase in bus fares.","His rude behaviour caused outrage among the other guests."]', 'B2', '["emotions","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (329, 'en', 'outstanding', 'adjective', '/aʊtˈstændɪŋ/', '杰出的；未解决的', 'extremely good; excellent', '["She received an award for her outstanding performance at work.","The view from the hotel room was absolutely outstanding."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (330, 'en', 'overcome', 'verb', '/ˌoʊvərˈkʌm/', '克服；战胜', 'to succeed in dealing with or controlling a problem', '["She overcame her fear of public speaking by practising regularly.","He had to overcome many difficulties to finish his degree."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (331, 'en', 'overlook', 'verb', '/ˌoʊvərˈlʊk/', '忽略；俯瞰', 'to fail to notice or consider something; to have a view of something from above', '["It''s easy to overlook small mistakes when you''re in a hurry.","Our balcony overlooks a beautiful garden."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (332, 'en', 'overseas', 'adverb', '/ˌoʊvərˈsiːz/', '在海外；在国外', 'in or to a foreign country, especially one across the sea', '["She''s been working overseas for the past three years.","Many students dream of studying overseas."]', 'B2', '["travel","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (333, 'en', 'overwhelming', 'adjective', '/ˌoʊvərˈwelmɪŋ/', '压倒性的；难以抗拒的', 'very great or very strong; so powerful that you cannot resist it', '["Starting a new job can feel overwhelming at first.","The response to the charity event was overwhelming."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (334, 'en', 'pale', 'adjective', '/peɪl/', '苍白的；浅色的', 'having skin that is light in colour, often because of illness or fear; light in colour', '["You look pale — are you feeling all right?","She painted the bedroom walls a pale blue."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (335, 'en', 'paradox', 'noun', '/ˈpærədɑːks/', '悖论；矛盾的事', 'a situation or statement that seems impossible or contradictory but may be true', '["It''s a paradox that the busiest people often find the most time to help.","The paradox of choice is that too many options can make us less happy."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (336, 'en', 'partly', 'adverb', '/ˈpɑːrtli/', '部分地；在某种程度上', 'to some extent; not completely', '["The delay was partly due to the bad weather.","I''m partly responsible for what happened."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (337, 'en', 'passport', 'noun', '/ˈpæspɔːrt/', '护照', 'an official document that identifies you as a citizen of a particular country and allows you to travel abroad', '["Make sure your passport is valid before you book your flight.","I need to renew my passport — it expires next month."]', 'B2', '["travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (338, 'en', 'patience', 'noun', '/ˈpeɪʃns/', '耐心；忍耐力', 'the ability to stay calm and accept a delay or something annoying without complaining', '["Learning a new language requires a lot of patience.","Thank you for your patience while we fix the issue."]', 'B2', '["emotions","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (339, 'en', 'peak', 'noun', '/piːk/', '顶峰；高峰', 'the highest point or level of something', '["Traffic reaches its peak between 8 and 9 in the morning.","She was at the peak of her career when she decided to retire."]', 'B2', '["work","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (340, 'en', 'peculiar', 'adjective', '/pɪˈkjuːliər/', '奇怪的；特有的', 'strange or unusual, especially in a way that is unpleasant or worrying', '["There''s a peculiar smell coming from the fridge.","He has a peculiar habit of talking to himself while cooking."]', 'B2', '["daily-life","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (341, 'en', 'penalty', 'noun', '/ˈpenəlti/', '处罚；罚款', 'a punishment for breaking a law, rule, or contract', '["There''s a penalty for returning library books late.","The company faced a heavy penalty for polluting the river."]', 'B2', '["law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (342, 'en', 'perceive', 'verb', '/pərˈsiːv/', '感知；认为', 'to notice or become aware of something; to understand something in a particular way', '["She perceived a change in his attitude after the argument.","The product is widely perceived as good value for money."]', 'B2', '["emotions","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (343, 'en', 'persistent', 'adjective', '/pərˈsɪstənt/', '坚持不懈的；持续的', 'continuing to do something despite difficulties; lasting for a long time', '["She was persistent in her search for a better job.","He has a persistent cough that won''t go away."]', 'B2', '["emotions","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (344, 'en', 'perspective', 'noun', '/pərˈspektɪv/', '观点；视角', 'a particular way of thinking about something; a point of view', '["Travelling gave me a new perspective on life.","Try to see things from her perspective before judging."]', 'B2', '["emotions","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (345, 'en', 'petition', 'noun', '/pəˈtɪʃn/', '请愿书；申请', 'a written document signed by many people that asks somebody in authority to do or change something', '["Over 5,000 people signed the petition to save the local park.","They started an online petition against the new parking rules."]', 'B2', '["politics","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (346, 'en', 'pharmaceutical', 'adjective', '/ˌfɑːrməˈsuːtɪkl/', '制药的；药学的', 'connected with making and selling drugs and medicines', '["She works for a pharmaceutical company that develops vaccines.","The pharmaceutical industry invests heavily in research."]', 'B2', '["health","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (347, 'en', 'phenomenon', 'noun', '/fɪˈnɑːmɪnɑːn/', '现象；奇迹', 'a fact or event in nature or society, especially one that is not fully understood', '["Social media has become a global phenomenon.","The northern lights are a spectacular natural phenomenon."]', 'B2', '["science","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (348, 'en', 'pioneer', 'noun', '/ˌpaɪəˈnɪr/', '先驱；开拓者', 'a person who is the first to study, develop, or do something new', '["She was a pioneer in the field of renewable energy.","The pioneers of the internet changed how we communicate."]', 'B2', '["science","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (349, 'en', 'pledge', 'verb', '/pledʒ/', '承诺；保证', 'to formally promise to give or do something', '["He pledged to donate 10% of his salary to charity.","The company pledged to reduce its carbon emissions by 2030."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (350, 'en', 'plunge', 'verb', '/plʌndʒ/', '骤降；跳入', 'to fall or move suddenly and quickly downward; to decrease suddenly', '["Temperatures plunged below zero last night.","She plunged into the swimming pool to cool off."]', 'B2', '["environment","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (351, 'en', 'portray', 'verb', '/pɔːrˈtreɪ/', '描绘；扮演', 'to describe or show somebody/something in a particular way; to act a part in a film or play', '["The film portrays life in a small village during the 1950s.","She was portrayed as a villain, but she''s actually very kind."]', 'B2', '["arts","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (352, 'en', 'pose', 'verb', '/poʊz/', '造成；摆姿势', 'to create a threat, problem, etc.; to sit or stand in a particular position for a photograph', '["Climate change poses a serious threat to coastal cities.","Everyone posed for a group photo at the wedding."]', 'B2', '["environment","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (353, 'en', 'possession', 'noun', '/pəˈzeʃn/', '拥有；财产', 'the state of having or owning something; a thing that you own', '["The house came into her possession after her grandmother passed away.","He packed all his possessions into two suitcases."]', 'B2', '["law","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (354, 'en', 'postpone', 'verb', '/poʊstˈpoʊn/', '推迟；延期', 'to arrange for something to take place at a later time or date', '["We had to postpone the picnic because of the rain.","The meeting has been postponed until next Monday."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (355, 'en', 'potential', 'adjective', '/pəˈtenʃl/', '潜在的；可能的', 'that can develop into something or be developed in the future', '["We need to be aware of potential risks before starting the project.","She''s a potential candidate for the manager position."]', 'B2', '["work","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (356, 'en', 'practitioner', 'noun', '/prækˈtɪʃənər/', '从业者；执业者', 'a person who works in a profession, especially medicine or law', '["You should consult a medical practitioner if the pain continues.","She''s a skilled practitioner of traditional Chinese medicine."]', 'B2', '["health","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (357, 'en', 'precaution', 'noun', '/prɪˈkɔːʃn/', '预防措施', 'something that is done in advance in order to prevent problems or to avoid danger', '["Take the precaution of wearing sunscreen, even on cloudy days.","As a precaution, the school cancelled outdoor activities during the storm."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (358, 'en', 'precisely', 'adverb', '/prɪˈsaɪsli/', '精确地；恰好', 'exactly; in an accurate and careful way', '["The train arrived at precisely 9:15, just as scheduled.","That''s precisely what I was trying to say."]', 'B2', '["communication","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (359, 'en', 'predictable', 'adjective', '/prɪˈdɪktəbl/', '可预测的；意料之中的', 'happening or behaving in a way that you would expect and therefore not interesting', '["The ending of the movie was too predictable.","His reaction was entirely predictable — he always gets upset about these things."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (360, 'en', 'predominantly', 'adverb', '/prɪˈdɑːmɪnəntli/', '主要地；占主导地位地', 'mostly; mainly', '["The audience was predominantly made up of young people.","The neighbourhood is predominantly residential with a few shops."]', 'B2', '["communication","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (361, 'en', 'prejudice', 'noun', '/ˈpredʒʊdɪs/', '偏见；歧视', 'an unreasonable dislike of or preference for a person, group, or thing, especially when it is not based on reason', '["We should fight against prejudice in all its forms.","She faced prejudice because of her accent when she moved to the city."]', 'B2', '["society","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (362, 'en', 'preliminary', 'adjective', '/prɪˈlɪmɪneri/', '初步的；预备的', 'happening before a more important action or event, especially in order to prepare for it', '["We need to do some preliminary research before writing the report.","The preliminary results of the survey look very promising."]', 'B2', '["science","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (363, 'en', 'premise', 'noun', '/ˈpremɪs/', '前提；假设', 'a statement or idea that forms the basis for an argument or theory', '["The premise of the book is that happiness comes from within.","His argument is based on a false premise."]', 'B2', '["education","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (364, 'en', 'prescribe', 'verb', '/prɪˈskraɪb/', '开处方；规定', 'to tell somebody to take a particular medicine or have a particular treatment; to say what should be done', '["The doctor prescribed some antibiotics for the infection.","The rules prescribe that all employees must wear ID badges."]', 'B2', '["health","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (365, 'en', 'prestigious', 'adjective', '/preˈstɪdʒəs/', '有声望的；享有盛誉的', 'respected and admired as very important or of very high quality', '["She graduated from a prestigious university in London.","He won a prestigious award for his photography."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (366, 'en', 'presumably', 'adverb', '/prɪˈzuːməbli/', '大概；想必', 'used to say that you think something is probably true', '["Presumably, he''ll call us when he arrives at the airport.","She''s not here, so presumably she''s still at work."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (367, 'en', 'prevail', 'verb', '/prɪˈveɪl/', '盛行；占优势', 'to exist or be very common at a particular time or in a particular place; to be accepted', '["A positive atmosphere prevails in the office since the new manager arrived.","Common sense prevailed and they decided to cancel the outdoor event."]', 'B2', '["society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (368, 'en', 'prevalent', 'adjective', '/ˈprevələnt/', '流行的；普遍的', 'that exists or is very common at a particular time or in a particular place', '["Allergies are becoming more prevalent among children.","Online shopping is now prevalent in most countries."]', 'B2', '["society","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (369, 'en', 'primarily', 'adverb', '/praɪˈmerəli/', '主要地；首先', 'mainly; for the most part', '["The website is designed primarily for young learners.","I bought the bike primarily for commuting to work."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (370, 'en', 'primitive', 'adjective', '/ˈprɪmətɪv/', '原始的；简陋的', 'belonging to a very simple society with no industry; very simple and old-fashioned', '["The cabin was fairly primitive — no electricity or running water.","Primitive tools were made from stone and wood."]', 'B2', '["society","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (371, 'en', 'prior', 'adjective', '/ˈpraɪər/', '先前的；优先的', 'happening or existing before something else or before a particular time', '["No prior experience is necessary for this course.","Please give us 24 hours'' prior notice if you need to cancel."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (372, 'en', 'privilege', 'noun', '/ˈprɪvəlɪdʒ/', '特权；荣幸', 'a special right or advantage that a particular person or group has', '["It was a privilege to meet such an inspiring speaker.","Not everyone has the privilege of receiving a good education."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (373, 'en', 'probe', 'verb', '/proʊb/', '探查；调查', 'to ask questions in order to find out secret or hidden information; to examine something closely', '["The journalist probed into the company''s financial records.","The doctor gently probed the injury to check for damage."]', 'B2', '["science","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (374, 'en', 'proceed', 'verb', '/proʊˈsiːd/', '继续进行；着手', 'to continue doing something; to go on to the next thing', '["Please proceed to the checkout when you''re ready.","After lunch, we proceeded with the rest of the meeting."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (375, 'en', 'productive', 'adjective', '/prəˈdʌktɪv/', '高效的；富有成效的', 'making goods or growing crops; achieving a lot', '["I''m usually more productive in the morning than in the afternoon.","We had a very productive meeting and made several decisions."]', 'B2', '["work","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (376, 'en', 'profound', 'adjective', '/prəˈfaʊnd/', '深刻的；意义深远的', 'very great; felt or experienced very strongly; showing great knowledge or understanding', '["The book had a profound impact on the way I think about relationships.","She expressed a profound sense of gratitude for all the support."]', 'B2', '["emotions","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (377, 'en', 'prohibit', 'verb', '/proʊˈhɪbɪt/', '禁止；阻止', 'to stop something from being done or used, especially by law', '["Smoking is prohibited inside the restaurant.","The rules prohibit the use of mobile phones during the exam."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (378, 'en', 'prominent', 'adjective', '/ˈprɑːmɪnənt/', '突出的；著名的', 'important or well known; easy to see or notice', '["She plays a prominent role in the local community.","The café is in a prominent location on the main street."]', 'B2', '["society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (379, 'en', 'prone', 'adjective', '/proʊn/', '易于……的；有……倾向的', 'likely to suffer from something or to do something bad', '["I''m prone to headaches when I don''t drink enough water.","Children are prone to catching colds in winter."]', 'B2', '["health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (380, 'en', 'proportion', 'noun', '/prəˈpɔːrʃn/', '比例；部分', 'a part or share of a whole; the relationship of one thing to another in terms of size or amount', '["A large proportion of the budget goes to rent.","The proportion of women in senior roles has increased."]', 'B2', '["science","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (381, 'en', 'prosecute', 'verb', '/ˈprɑːsɪkjuːt/', '起诉；检举', 'to officially charge somebody with a crime in court', '["Shoplifters will be prosecuted.","The company was prosecuted for breaking environmental laws."]', 'B2', '["law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (382, 'en', 'prospective', 'adjective', '/prəˈspektɪv/', '预期的；未来的', 'expected to do something or to become something', '["We showed several prospective buyers around the house.","Prospective students are invited to visit the campus this weekend."]', 'B2', '["business","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (383, 'en', 'prosperity', 'noun', '/prɑːˈsperəti/', '繁荣；兴旺', 'the state of being successful, especially in making money', '["The town has enjoyed a period of prosperity since the new factory opened.","Education is often seen as the key to prosperity."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (384, 'en', 'provision', 'noun', '/prəˈvɪʒn/', '供应；条款；规定', 'the act of supplying somebody with something; a condition or arrangement in a legal document', '["The hotel makes provision for guests with special dietary needs.","There is no provision in the contract for early termination."]', 'B2', '["law","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (385, 'en', 'provoke', 'verb', '/prəˈvoʊk/', '激怒；引起', 'to cause a particular reaction or feeling; to deliberately annoy somebody', '["His comments provoked a heated debate among the team.","Don''t let him provoke you — just walk away."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (386, 'en', 'pursuit', 'noun', '/pərˈsuːt/', '追求；追赶', 'the act of looking for or trying to find something; an activity that you do for pleasure', '["She left her corporate job in pursuit of her dream to become an artist.","Outdoor pursuits like hiking and cycling are popular here."]', 'B2', '["daily-life","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (387, 'en', 'qualified', 'adjective', '/ˈkwɑːlɪfaɪd/', '有资格的；合格的', 'having the training or experience needed to do a particular job; having passed the exams needed', '["She''s a fully qualified dentist with ten years of experience.","Only qualified candidates will be invited for an interview."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (388, 'en', 'questionnaire', 'noun', '/ˌkwestʃəˈner/', '问卷；调查表', 'a written list of questions that are answered by a number of people so that information can be collected', '["Please fill out this short questionnaire about your shopping habits.","The company sent out a customer satisfaction questionnaire."]', 'B2', '["science","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (389, 'en', 'radical', 'adjective', '/ˈrædɪkl/', '根本的；激进的', 'relating to the most basic and important parts of something; favouring extreme changes', '["The company needs to make radical changes to survive.","Her radical ideas about education attracted a lot of attention."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (390, 'en', 'rage', 'noun', '/reɪdʒ/', '愤怒；狂怒', 'a feeling of violent anger that is difficult to control', '["He was shaking with rage after someone scratched his car.","Road rage is becoming an increasing problem in big cities."]', 'B2', '["emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (391, 'en', 'random', 'adjective', '/ˈrændəm/', '随机的；任意的', 'done, chosen, or happening without any particular method, pattern, or purpose', '["The winners were selected at random from all the entries.","She asked me a random question about my favourite colour."]', 'B2', '["science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (392, 'en', 'rational', 'adjective', '/ˈræʃənl/', '理性的；合理的', 'based on reason rather than emotions', '["Let''s try to have a calm, rational discussion about this.","There must be a rational explanation for what happened."]', 'B2', '["emotions","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (393, 'en', 'readily', 'adverb', '/ˈredɪli/', '容易地；乐意地', 'quickly and without difficulty; willingly', '["Fresh ingredients are readily available at the local market.","She readily agreed to help us move house."]', 'B2', '["daily-life","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (394, 'en', 'realm', 'noun', '/relm/', '领域；范围', 'an area of activity, interest, or knowledge', '["Her question was outside the realm of my expertise.","In the realm of cooking, she is truly gifted."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (395, 'en', 'reassure', 'verb', '/ˌriːəˈʃʊr/', '使安心；安慰', 'to say or do something in order to make somebody feel less frightened or worried', '["The doctor reassured me that the test results were perfectly normal.","He put his arm around her to reassure her that everything would be fine."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (396, 'en', 'sake', 'noun', '/seɪk/', '缘故；目的', 'used to express the purpose or reason for something', '["For the sake of your health, you should quit smoking.","They stayed together for the children''s sake."]', 'B2', '["relationships","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (397, 'en', 'scarcely', 'adverb', '/ˈskeəsli/', '几乎不；刚刚', 'only just; almost not', '["I could scarcely believe it when I won the competition.","He had scarcely sat down when the phone rang."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (398, 'en', 'scatter', 'verb', '/ˈskætər/', '散开；撒', 'to throw or drop things in different directions so that they cover an area; to move apart in different directions', '["She scattered flower seeds across the garden.","The crowd scattered when the rain started pouring."]', 'B2', '["daily-life","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (399, 'en', 'sceptical', 'adjective', '/ˈskeptɪkl/', '怀疑的；多疑的', 'having doubts that something is true or that something will happen', '["I''m sceptical about the benefits of this new diet.","Many people remain sceptical that the changes will make any difference."]', 'B2', '["emotions","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (400, 'en', 'seemingly', 'adverb', '/ˈsiːmɪŋli/', '看似；表面上', 'in a way that appears to be true but may not be', '["He was seemingly calm, but inside he was very nervous.","The task was seemingly impossible, but we managed to finish it."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (401, 'en', 'seize', 'verb', '/siːz/', '抓住；没收', 'to take hold of something suddenly and firmly; to take something using official power', '["She seized his arm and pulled him back from the road.","Customs officers seized a large quantity of smuggled goods."]', 'B2', '["law","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (402, 'en', 'sensation', 'noun', '/senˈseɪʃn/', '感觉；轰动', 'a feeling that you get from one of your five senses; great surprise, excitement, or interest', '["I felt a burning sensation in my throat after eating the spicy soup.","The new restaurant became an overnight sensation in the city."]', 'B2', '["emotions","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (403, 'en', 'setback', 'noun', '/ˈsetbæk/', '挫折；阻碍', 'a difficulty or problem that delays or prevents progress', '["Losing my job was a major setback, but I kept looking.","Despite several setbacks, the project was completed on time."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (404, 'en', 'shallow', 'adjective', '/ˈʃæləʊ/', '浅的；肤浅的', 'not having much distance between the top and the bottom; not showing serious thought or deep feeling', '["The kids played in the shallow end of the swimming pool.","I think judging people by their looks is quite shallow."]', 'B2', '["daily-life","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (405, 'en', 'sharply', 'adverb', '/ˈʃɑːrpli/', '急剧地；尖锐地', 'suddenly and by a large amount; in a critical or disapproving way', '["Prices have risen sharply over the past few months.","She spoke sharply to the children when they misbehaved."]', 'B2', '["business","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (406, 'en', 'shed', 'verb', '/ʃed/', '流出；脱落；摆脱', 'to get rid of something that is no longer wanted; to let something fall or flow', '["She shed a few tears when she said goodbye to her friends.","The dog sheds a lot of hair in the summer."]', 'B2', '["daily-life","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (407, 'en', 'sheer', 'adjective', '/ʃɪər/', '纯粹的；陡峭的', 'used to emphasize the size, degree, or amount of something; very steep', '["The sheer volume of emails I get every day is overwhelming.","We stood at the edge of a sheer cliff looking down at the sea."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (408, 'en', 'shelter', 'noun', '/ˈʃeltər/', '避难所；庇护', 'a place that provides protection from bad weather or danger', '["We took shelter under a tree when it started to rain.","The charity runs a shelter for homeless people in the city centre."]', 'B2', '["society","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (409, 'en', 'shrink', 'verb', '/ʃrɪŋk/', '缩小；收缩', 'to become smaller, or to make something smaller in size or amount', '["My favourite sweater shrank in the wash because I used hot water.","The company''s market share has been shrinking steadily."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (410, 'en', 'significant', 'adjective', '/sɪɡˈnɪfɪkənt/', '重要的；显著的', 'large or important enough to have an effect or to be noticed', '["There has been a significant improvement in her grades this term.","The discovery was significant for medical research."]', 'B2', '["science","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (411, 'en', 'simultaneously', 'adverb', '/ˌsɪmlˈteɪniəsli/', '同时地', 'at the same time as something else', '["She was talking on the phone and cooking dinner simultaneously.","The film was released simultaneously in twenty countries."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (412, 'en', 'soar', 'verb', '/sɔːr/', '猛增；高飞', 'to rise very quickly to a high level; to fly high in the air', '["House prices have soared in the past few years.","The eagle soared high above the valley."]', 'B2', '["business","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (413, 'en', 'solely', 'adverb', '/ˈsəʊlli/', '仅仅；唯一地', 'only; not involving anything or anyone else', '["She was solely responsible for organizing the whole event.","I''m not solely to blame for what happened."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (414, 'en', 'somewhat', 'adverb', '/ˈsʌmwɒt/', '有点；稍微', 'to some degree; a little', '["The restaurant was somewhat disappointing for the price.","I was somewhat surprised to hear she had quit her job."]', 'B2', '["daily-life","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (415, 'en', 'sophisticated', 'adjective', '/səˈfɪstɪkeɪtɪd/', '复杂精密的；老练的', 'having a lot of experience of the world and knowing about fashion, culture, etc.; cleverly designed and complex', '["She has very sophisticated taste in art and music.","Modern smartphones use increasingly sophisticated technology."]', 'B2', '["technology","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (416, 'en', 'soul', 'noun', '/səʊl/', '灵魂；心灵', 'the spiritual part of a person, believed to exist after death; the inner character of a person', '["Music really speaks to my soul.","She poured her heart and soul into her cooking."]', 'B2', '["emotions","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (417, 'en', 'spare', 'adjective', '/speər/', '多余的；备用的', 'not being used; kept in case you need to replace one that is being used', '["Do you have a spare charger I could borrow?","I like to read in my spare time."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (418, 'en', 'specification', 'noun', '/ˌspesɪfɪˈkeɪʃn/', '规格；规范', 'a detailed description of how something should be designed or made', '["The laptop meets all the specifications I need for video editing.","The house was built to exact specifications."]', 'B2', '["technology","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (419, 'en', 'speculate', 'verb', '/ˈspekjuleɪt/', '推测；投机', 'to form an opinion about something without knowing all the details or facts', '["It''s too early to speculate about what caused the accident.","People began speculating whether the couple would get married."]', 'B2', '["business","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (420, 'en', 'split', 'verb', '/splɪt/', '分裂；分开', 'to divide or to make something divide into two or more parts', '["Let''s split the bill — it''s easier that way.","The road splits into two just after the bridge."]', 'B2', '["daily-life","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (421, 'en', 'spouse', 'noun', '/spaʊs/', '配偶', 'a husband or wife', '["Employees can add their spouse to the health insurance plan.","Both spouses need to sign the mortgage agreement."]', 'B2', '["relationships","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (422, 'en', 'squeeze', 'verb', '/skwiːz/', '挤；挤压', 'to press something firmly, especially with your fingers; to get into or through a small space', '["She squeezed some lemon juice over the salad.","I managed to squeeze into the last seat on the bus."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (423, 'en', 'stability', 'noun', '/stəˈbɪləti/', '稳定性；稳固', 'the quality or state of being steady and not changing or being disturbed', '["Children need stability and routine in their daily lives.","The new manager brought stability to the team."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (424, 'en', 'stain', 'noun', '/steɪn/', '污渍；污点', 'a dirty mark on something that is difficult to remove', '["I can''t get this coffee stain out of my white shirt.","There were grease stains all over the kitchen counter."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (425, 'en', 'stake', 'noun', '/steɪk/', '利害关系；股份', 'something important that might be won or lost; a share or interest in a business', '["There''s a lot at stake in tomorrow''s job interview.","She owns a 20% stake in the family business."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (426, 'en', 'starve', 'verb', '/stɑːrv/', '挨饿；饿死', 'to suffer or die because you do not have enough food to eat', '["I forgot to eat lunch and now I''m absolutely starving.","Millions of people around the world are starving."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (427, 'en', 'steadily', 'adverb', '/ˈstedɪli/', '稳定地；持续地', 'in a gradual, regular way; without stopping or changing', '["The temperature has been rising steadily all week.","She worked steadily through the night to finish the report."]', 'B2', '["daily-life","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (428, 'en', 'steep', 'adjective', '/stiːp/', '陡峭的；急剧的', 'rising or falling quickly, not gradually; (of a price or demand) too much; unreasonable', '["The path up the hill is very steep, so wear good shoes.","The restaurant was nice, but the prices were quite steep."]', 'B2', '["travel","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (429, 'en', 'stem', 'verb', '/stem/', '阻止；起源于', 'to stop something from spreading or increasing; to be caused by something', '["Her fear of dogs stems from an incident in her childhood.","The government is trying to stem the flow of illegal goods."]', 'B2', '["daily-life","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (430, 'en', 'stereotype', 'noun', '/ˈsteriətaɪp/', '刻板印象；成见', 'a fixed idea or image that many people have of a particular type of person or thing, but which is often not true in reality', '["We should challenge stereotypes rather than accept them.","The film breaks the stereotype that older people can''t learn new things."]', 'B2', '["society","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (431, 'en', 'stiff', 'adjective', '/stɪf/', '僵硬的；严厉的', 'difficult to bend or move; not relaxed or friendly; severe', '["My neck feels stiff because I slept in an awkward position.","The company faces stiff competition from online retailers."]', 'B2', '["health","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (432, 'en', 'stimulus', 'noun', '/ˈstɪmjələs/', '刺激；激励', 'something that helps somebody or something to develop better or more quickly; something that produces a reaction in the body', '["The tax cut acted as a stimulus for economic growth.","Young children need lots of visual stimuli to learn."]', 'B2', '["business","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (433, 'en', 'strain', 'noun', '/streɪn/', '压力；拉伤', 'pressure on somebody or something because they have too much to do or manage; an injury caused by stretching a muscle too much', '["Working two jobs put a lot of strain on her health.","He suffered a muscle strain while playing football."]', 'B2', '["health","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (434, 'en', 'strategic', 'adjective', '/strəˈtiːdʒɪk/', '战略的；策略的', 'done as part of a plan that is meant to achieve a particular purpose; relating to strategy', '["We need to make strategic decisions about the future of the company.","The cafe is in a strategic location near the train station."]', 'B2', '["business","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (435, 'en', 'strictly', 'adverb', '/ˈstrɪktli/', '严格地；完全地', 'in a way that must be obeyed completely; used to emphasize that something is true in every way', '["Parking here is strictly forbidden.","Strictly speaking, a tomato is a fruit, not a vegetable."]', 'B2', '["law","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (436, 'en', 'strive', 'verb', '/straɪv/', '努力；奋斗', 'to try very hard to achieve something', '["She always strives to do her best at work.","We should strive for a better work-life balance."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (437, 'en', 'stunning', 'adjective', '/ˈstʌnɪŋ/', '令人惊叹的；极漂亮的', 'extremely attractive or impressive', '["The view from the top of the mountain was absolutely stunning.","She looked stunning in her wedding dress."]', 'B2', '["arts","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (438, 'en', 'subject', 'adjective', '/ˈsʌbdʒɪkt/', '受制于的；取决于的', 'likely to be affected by something, especially something bad; depending on something in order to happen', '["The plan is subject to approval from the manager.","All flights are subject to delay during bad weather."]', 'B2', '["law","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (439, 'en', 'submit', 'verb', '/səbˈmɪt/', '提交；服从', 'to give a document, proposal, etc. to somebody in authority so that they can study or consider it', '["You need to submit your assignment by Friday.","She submitted her application for the job online."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (440, 'en', 'subsequent', 'adjective', '/ˈsʌbsɪkwənt/', '随后的；后来的', 'happening or coming after something else', '["The mistake was corrected in subsequent editions of the book.","She got a promotion and a subsequent pay rise."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (441, 'en', 'substantially', 'adverb', '/səbˈstænʃəli/', '大量地；实质上', 'to a great extent; by a large amount', '["House prices have increased substantially this year.","The two reports are substantially different from each other."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (442, 'en', 'substitute', 'noun', '/ˈsʌbstɪtjuːt/', '替代品；替补', 'a person or thing that you use or have instead of the one you normally use or have', '["You can use honey as a substitute for sugar in this recipe.","The substitute teacher was really nice and funny."]', 'B2', '["daily-life","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (443, 'en', 'subtle', 'adjective', '/ˈsʌtl/', '微妙的；精巧的', 'not very noticeable or obvious; behaving in a clever way to achieve what you want', '["There is a subtle difference between the two colours.","The flavour of the sauce is subtle but delicious."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (444, 'en', 'succession', 'noun', '/səkˈseʃn/', '连续；继承', 'a number of people or things that follow each other in time or order; the act of getting a position after somebody else', '["A succession of bad decisions led to the company''s failure.","She won the championship for the third time in succession."]', 'B2', '["business","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (445, 'en', 'sufficient', 'adjective', '/səˈfɪʃnt/', '足够的；充分的', 'enough for a particular purpose', '["Make sure you drink sufficient water during exercise.","We didn''t have sufficient time to finish the project."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (446, 'en', 'superb', 'adjective', '/suːˈpɜːrb/', '极好的；卓越的', 'excellent; of very high quality', '["The hotel had superb views of the ocean.","She did a superb job organizing the birthday party."]', 'B2', '["daily-life","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (447, 'en', 'suppress', 'verb', '/səˈpres/', '压制；抑制', 'to prevent something from being published or made known; to prevent yourself from having or expressing a feeling', '["She tried hard to suppress a yawn during the boring meeting.","He suppressed his anger and spoke calmly."]', 'B2', '["emotions","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (448, 'en', 'surge', 'noun', '/sɜːrdʒ/', '激增；涌动', 'a sudden large increase in something; a sudden strong feeling', '["There has been a surge in online shopping during the holidays.","She felt a surge of excitement when she got the acceptance letter."]', 'B2', '["business","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (449, 'en', 'surplus', 'noun', '/ˈsɜːrpləs/', '剩余；盈余', 'an amount that is extra or more than you need', '["The country has a trade surplus this year.","We donated the surplus food to the local food bank."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (450, 'en', 'surrender', 'verb', '/səˈrendər/', '投降；放弃', 'to admit that you have been defeated and want to stop fighting; to give something to somebody else', '["The army was forced to surrender after running out of supplies.","You must surrender your passport at the check-in desk."]', 'B2', '["politics","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (451, 'en', 'sustain', 'verb', '/səˈsteɪn/', '维持；承受', 'to make something continue for a period of time; to suffer something unpleasant', '["It''s hard to sustain your energy levels without eating properly.","The building sustained serious damage in the earthquake."]', 'B2', '["environment","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (452, 'en', 'sustainable', 'adjective', '/səˈsteɪnəbl/', '可持续的', 'involving the use of natural products and energy in a way that does not harm the environment', '["We need to find more sustainable ways of living.","The company is committed to sustainable packaging."]', 'B2', '["environment","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (453, 'en', 'swallow', 'verb', '/ˈswɒləʊ/', '吞咽；忍受', 'to make food, drink, etc. go down your throat to your stomach', '["The pill was so big that it was hard to swallow.","He swallowed his pride and asked for help with the project."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (454, 'en', 'swear', 'verb', '/sweər/', '发誓；咒骂', 'to make a serious promise to do something; to use rude or offensive language', '["I swear I''ll pay you back by the end of the month.","He swore loudly when he stubbed his toe on the table."]', 'B2', '["communication","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (455, 'en', 'swift', 'adjective', '/swɪft/', '迅速的；敏捷的', 'happening or done quickly and immediately; moving very quickly', '["The emergency team made a swift response to the fire.","With a swift movement, she caught the falling glass."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (456, 'en', 'symbolic', 'adjective', '/sɪmˈbɒlɪk/', '象征性的；符号的', 'containing symbols or used as a symbol; representing something important', '["The dove is symbolic of peace.","The gift was small but symbolic of their friendship."]', 'B2', '["arts","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (457, 'en', 'sympathy', 'noun', '/ˈsɪmpəθi/', '同情；理解', 'the feeling of being sorry for somebody; showing that you understand and care about somebody''s problems', '["I have a lot of sympathy for people who work night shifts.","He sent a card to express his sympathy after her loss."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (458, 'en', 'tackle', 'verb', '/ˈtækl/', '处理；应对', 'to make a determined effort to deal with a difficult problem or situation', '["We need to tackle the problem of food waste in our household.","The government promised to tackle rising housing costs."]', 'B2', '["work","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (459, 'en', 'tempt', 'verb', '/tempt/', '引诱；吸引', 'to attract somebody or make somebody want to do or have something, even if they know it is wrong', '["The smell of fresh bread tempted me into the bakery.","I was tempted to skip the gym, but I went anyway."]', 'B2', '["emotions","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (460, 'en', 'tendency', 'noun', '/ˈtendənsi/', '倾向；趋势', 'a way of behaving or doing things that is developing and becoming more common; the likelihood of behaving in a particular way', '["He has a tendency to arrive late for meetings.","There is a growing tendency for people to shop online."]', 'B2', '["society","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (461, 'en', 'tense', 'adjective', '/tens/', '紧张的；绷紧的', 'feeling nervous, worried, and not able to relax; making you feel anxious', '["The atmosphere at dinner was very tense after the argument.","My shoulders are really tense from sitting at my desk all day."]', 'B2', '["emotions","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (462, 'en', 'territory', 'noun', '/ˈterətɔːri/', '领土；领域', 'an area of land that belongs to or is controlled by a government or person; an area of knowledge or experience', '["The cat marked its territory by scratching the fence.","Starting a business was unfamiliar territory for her."]', 'B2', '["politics","travel"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (463, 'en', 'texture', 'noun', '/ˈtekstʃər/', '质地；纹理', 'the way a surface, substance, or piece of cloth feels when you touch it', '["This moisturizer has a lovely smooth texture.","The cake had a light, fluffy texture that melted in your mouth."]', 'B2', '["daily-life","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (464, 'en', 'thereafter', 'adverb', '/ˌðeərˈɑːftər/', '此后；之后', 'after the time or event mentioned', '["He moved to London in 2015 and lived there for ten years thereafter.","She got her driving licence and shortly thereafter bought a car."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (465, 'en', 'thereby', 'adverb', '/ˌðeərˈbaɪ/', '因此；从而', 'used to introduce the result of the action or situation mentioned', '["She cycled to work, thereby saving money on petrol.","He finished the project early, thereby impressing his boss."]', 'B2', '["daily-life","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (466, 'en', 'thorough', 'adjective', '/ˈθʌrə/', '彻底的；详尽的', 'done carefully and completely, covering every detail', '["The doctor gave me a thorough examination.","She did a thorough job of cleaning the entire house."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (467, 'en', 'thoroughly', 'adverb', '/ˈθʌrəli/', '彻底地；完全地', 'completely and carefully; very much', '["Make sure you wash your hands thoroughly before cooking.","I thoroughly enjoyed the film — it was brilliant."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (468, 'en', 'though', 'conjunction', '/ðəʊ/', '虽然；不过', 'used to introduce a fact or opinion that contrasts with something that has been said', '["Though the exam was difficult, I think I passed.","I really enjoyed the meal, though it was a bit expensive."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (469, 'en', 'throughout', 'preposition', '/θruːˈaʊt/', '贯穿；遍及', 'in or into every part of something; during the whole period of time of something', '["The hotel offers free Wi-Fi throughout the building.","She remained cheerful throughout the difficult process."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (470, 'en', 'thrive', 'verb', '/θraɪv/', '繁荣；茁壮成长', 'to become, and continue to be, successful, strong, or healthy', '["These plants thrive in warm, sunny conditions.","Children thrive when they receive love and encouragement."]', 'B2', '["environment","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (471, 'en', 'thus', 'adverb', '/ðʌs/', '因此；如此', 'in this way; as a result of something just mentioned', '["She studied hard and thus passed all her exams.","The shop was closed and thus we couldn''t buy any groceries."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (472, 'en', 'till', 'conjunction', '/tɪl/', '直到', 'up to the point in time mentioned; until', '["I''ll wait here till you get back from the shop.","We didn''t stop driving till we reached the coast."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (473, 'en', 'tolerance', 'noun', '/ˈtɒlərəns/', '容忍；宽容', 'the willingness to accept behaviour and beliefs that are different from your own', '["We should show tolerance towards people with different opinions.","He has a low tolerance for spicy food."]', 'B2', '["society","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (474, 'en', 'trace', 'verb', '/treɪs/', '追踪；追溯', 'to find or discover somebody or something by looking for them carefully; to find the origin of something', '["The police managed to trace the missing person through social media.","She traced her family history back to the 18th century."]', 'B2', '["law","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (475, 'en', 'trait', 'noun', '/treɪt/', '特征；特点', 'a particular quality in your personality; a particular quality of something', '["Kindness is one of her best personality traits.","Creativity is a valuable trait in any profession."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (476, 'en', 'transform', 'verb', '/trænsˈfɔːrm/', '转变；改造', 'to change the form, appearance, or character of something or somebody completely', '["We transformed the spare room into a home office.","Travelling abroad completely transformed my perspective on life."]', 'B2', '["daily-life","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (477, 'en', 'transition', 'noun', '/trænˈzɪʃn/', '过渡；转变', 'the process or a period of changing from one state or condition to another', '["The transition from school to university can be challenging.","The country is going through a period of economic transition."]', 'B2', '["education","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (478, 'en', 'transparent', 'adjective', '/trænsˈpærənt/', '透明的；坦率的', 'allowing you to see through it; easy to understand; not trying to hide anything', '["The water in the lake was so clear and transparent.","The company promises to be transparent about how it uses customer data."]', 'B2', '["business","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (479, 'en', 'tremendous', 'adjective', '/trəˈmendəs/', '巨大的；极好的', 'very great in amount, size, or degree; extremely good', '["She has made tremendous progress in learning English.","The concert was a tremendous success."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (480, 'en', 'trigger', 'verb', '/ˈtrɪɡər/', '引发；触发', 'to cause something to happen suddenly', '["The smoke triggered the fire alarm in the kitchen.","Eating too much sugar can trigger headaches for some people."]', 'B2', '["health","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (481, 'en', 'trivial', 'adjective', '/ˈtrɪviəl/', '琐碎的；微不足道的', 'not important or serious; not worth considering', '["Don''t waste your time arguing about trivial matters.","It may seem trivial, but little things can make a big difference."]', 'B2', '["daily-life","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (482, 'en', 'truly', 'adverb', '/ˈtruːli/', '真正地；确实', 'used to emphasize that something is really or genuinely the case', '["I truly believe this is the best decision for our family.","It was a truly unforgettable holiday."]', 'B2', '["communication","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (483, 'en', 'trustworthy', 'adjective', '/ˈtrʌstwɜːrði/', '值得信赖的；可靠的', 'that you can rely on to be good, honest, and sincere', '["She''s very trustworthy — you can tell her anything.","It''s important to find a trustworthy babysitter for your children."]', 'B2', '["relationships","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (484, 'en', 'undergo', 'verb', '/ˌʌndərˈɡəʊ/', '经历；接受', 'to experience something, especially a change or something unpleasant', '["She had to undergo surgery on her knee after the accident.","The building is undergoing major renovations."]', 'B2', '["health","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (485, 'en', 'underlying', 'adjective', '/ˌʌndərˈlaɪɪŋ/', '潜在的；根本的', 'important in a situation but not always easily noticed or stated clearly', '["Stress was the underlying cause of his health problems.","There are underlying issues that we need to address."]', 'B2', '["science","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (486, 'en', 'undoubtedly', 'adverb', '/ʌnˈdaʊtɪdli/', '毫无疑问地；无疑', 'used to say that something is definitely true or that something is certain to happen', '["She is undoubtedly one of the best teachers in the school.","This will undoubtedly be the most difficult exam of the year."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (487, 'en', 'unfair', 'adjective', '/ˌʌnˈfeər/', '不公平的；不合理的', 'not right or equal in a way that treats people badly or that gives some people more advantage than others', '["It''s unfair that she gets paid less for doing the same job.","The children complained that the rules were unfair."]', 'B2', '["society","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (488, 'en', 'unlike', 'preposition', '/ˌʌnˈlaɪk/', '不像；与...不同', 'different from a particular person or thing; not typical of somebody or something', '["Unlike her sister, she prefers staying at home to going out.","It''s unlike him to be so quiet — I wonder what''s wrong."]', 'B2', '["communication","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (489, 'en', 'uphold', 'verb', '/ʌpˈhəʊld/', '维护；支持', 'to support something that you think is right and make sure it continues to exist', '["We must uphold the values of fairness and respect.","The court upheld the original decision."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (490, 'en', 'utter', 'adjective', '/ˈʌtər/', '完全的；彻底的', 'used to emphasize how complete something is', '["The whole trip was an utter disaster from start to finish.","She stared at him in utter disbelief."]', 'B2', '["emotions","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (491, 'en', 'vacant', 'adjective', '/ˈveɪkənt/', '空的；空缺的', 'not being used; available to be used; (of a job) available for somebody to do', '["There are several vacant apartments in this building.","The position has been vacant for three months now."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (492, 'en', 'vague', 'adjective', '/veɪɡ/', '模糊的；含糊的', 'not clear in a person''s mind; not having a clear meaning or giving enough information', '["She gave a rather vague answer when I asked about her plans.","I only have a vague memory of visiting that place as a child."]', 'B2', '["communication","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (493, 'en', 'valid', 'adjective', '/ˈvælɪd/', '有效的；合理的', 'based on what is logical or true; legally or officially acceptable', '["You make a very valid point about the cost.","Make sure your passport is still valid before you book the flight."]', 'B2', '["law","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (494, 'en', 'vanish', 'verb', '/ˈvænɪʃ/', '消失；消亡', 'to disappear suddenly and completely', '["My keys seem to have vanished — I can''t find them anywhere.","The magician made the rabbit vanish right before our eyes."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (495, 'en', 'whereas', 'conjunction', '/ˌweərˈæz/', '然而；鉴于', 'used to compare or contrast two facts or situations', '["She likes coffee, whereas her husband prefers tea.","I enjoy cooking, whereas my sister prefers eating out."]', 'B2', '["communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (496, 'en', 'workforce', 'noun', '/ˈwɜːrkfɔːrs/', '劳动力；全体员工', 'all the people who work in a company, industry, or country', '["The company plans to reduce its workforce by ten percent.","Women now make up nearly half of the workforce."]', 'B2', '["work","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (497, 'en', 'yield', 'verb', '/jiːld/', '产生；屈服', 'to produce or provide something; to give way to pressure', '["The research yielded some interesting results.","He refused to yield to pressure from his colleagues."]', 'B2', '["science","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (498, 'en', 'widespread', 'adjective', '/ˈwaɪdspred/', '广泛的；普遍的', 'existing or happening in many places or among many people', '["There is widespread concern about rising food prices.","The disease became widespread during the winter months."]', 'B2', '["society","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (499, 'en', 'withdraw', 'verb', '/wɪðˈdrɔː/', '撤回；提取', 'to take money out of a bank account; to move back from a place', '["She withdrew some money from her savings account.","The army was forced to withdraw from the region."]', 'B2', '["business","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (500, 'en', 'witness', 'noun', '/ˈwɪtnəs/', '目击者；证人', 'a person who sees something happen and can describe it to others', '["The police are looking for witnesses to the accident.","She was called as a witness in the court case."]', 'B2', '["law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (502, 'en', 'acquire', 'verb', '/əˈkwaɪər/', '获得；习得', 'to obtain something by buying it or being given it', '["He acquired a taste for Italian food while living in Rome.","The company acquired two smaller businesses last year."]', 'B2', '["business","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (503, 'en', 'addiction', 'noun', '/əˈdɪkʃn/', '上瘾；沉溺', 'the condition of being unable to stop using or doing something harmful', '["His addiction to video games was affecting his schoolwork.","The clinic helps people recover from drug addiction."]', 'B2', '["health","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (504, 'en', 'admire', 'verb', '/ədˈmaɪər/', '钦佩；赞赏', 'to respect somebody for what they have done or to look at something with pleasure', '["I really admire her courage in speaking out.","We stopped to admire the beautiful view from the top of the hill."]', 'B2', '["emotions","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (505, 'en', 'adolescent', 'noun', '/ˌædəˈlesnt/', '青少年', 'a young person who is developing from a child into an adult', '["Many adolescents struggle with issues of identity.","The program is designed for adolescents between 12 and 18."]', 'B2', '["education","health"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (506, 'en', 'adverse', 'adjective', '/ˈædvɜːrs/', '不利的；有害的', 'negative and unpleasant; likely to cause problems or harm', '["The drug can have adverse effects on your health.","Adverse weather conditions forced us to cancel the trip."]', 'B2', '["health","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (508, 'en', 'affordable', 'adjective', '/əˈfɔːrdəbl/', '负担得起的', 'cheap enough for most people to be able to buy', '["We need more affordable housing in this city.","The restaurant serves good food at affordable prices."]', 'B2', '["business","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (509, 'en', 'agenda', 'noun', '/əˈdʒendə/', '议程；日程', 'a list of items to be discussed at a meeting; a plan of things to be done', '["The first item on the agenda is the budget report.","Education reform is high on the government''s agenda."]', 'B2', '["work","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (511, 'en', 'agricultural', 'adjective', '/ˌæɡrɪˈkʌltʃərəl/', '农业的', 'connected with the science or practice of farming', '["The region depends heavily on agricultural production.","New agricultural methods have helped farmers grow more food."]', 'B2', '["environment","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (512, 'en', 'alien', 'adjective', '/ˈeɪliən/', '外国的；陌生的', 'strange and frightening; different from what you are used to', '["The concept of personal space is alien to some cultures.","She felt like an alien in her new school."]', 'B2', '["society","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (513, 'en', 'allegation', 'noun', '/ˌæləˈɡeɪʃn/', '指控；说法', 'a public statement that somebody has done something wrong, without proof', '["He denied all allegations of wrongdoing.","The newspaper published serious allegations against the company."]', 'B2', '["law","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (515, 'en', 'alliance', 'noun', '/əˈlaɪəns/', '联盟；同盟', 'an agreement between countries, groups, or people to work together', '["The two countries formed a military alliance.","She built an alliance with other managers to push for change."]', 'B2', '["politics","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (516, 'en', 'alongside', 'preposition', '/əˌlɔːŋˈsaɪd/', '在……旁边；与……一起', 'next to or together with somebody or something', '["She worked alongside her colleagues on the project.","New houses were built alongside the river."]', 'B2', '["work","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (517, 'en', 'ambitious', 'adjective', '/æmˈbɪʃəs/', '有野心的；雄心勃勃的', 'having a strong desire to be successful, powerful, or rich', '["She is very ambitious and wants to become a CEO one day.","The city announced an ambitious plan to build a new airport."]', 'B2', '["work","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (518, 'en', 'amendment', 'noun', '/əˈmendmənt/', '修正案；修改', 'a small change or improvement made to a law, document, or statement', '["The committee proposed an amendment to the new law.","Several amendments were made to the original plan."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (519, 'en', 'amid', 'preposition', '/əˈmɪd/', '在……之中', 'in the middle of something; while something else is happening', '["The company grew amid tough economic conditions.","She remained calm amid all the confusion."]', 'B2', '["daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (520, 'en', 'ancestor', 'noun', '/ˈænsestər/', '祖先；祖宗', 'a person in your family who lived a long time before you', '["My ancestors came from a small village in southern China.","Scientists believe that humans and apes share a common ancestor."]', 'B2', '["relationships","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (521, 'en', 'anniversary', 'noun', '/ˌænɪˈvɜːrsəri/', '周年纪念日', 'a date on which an important event happened in a previous year', '["They celebrated their tenth wedding anniversary last month.","The school held a special event for its 50th anniversary."]', 'B2', '["relationships","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (522, 'en', 'anonymous', 'adjective', '/əˈnɑːnɪməs/', '匿名的', 'with a name that is not known or made public', '["The donation was made by an anonymous supporter.","She wrote an anonymous letter to the newspaper."]', 'B2', '["communication","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (528, 'en', 'archive', 'noun', '/ˈɑːrkaɪv/', '档案；档案馆', 'a collection of historical records or documents; a place where they are stored', '["The national archive contains records dating back 300 years.","Old photographs were discovered in the company''s archive."]', 'B2', '["education","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (529, 'en', 'arena', 'noun', '/əˈriːnə/', '竞技场；领域', 'a large area for sports or entertainment; an area of activity or competition', '["The concert was held in a large indoor arena.","She is well known in the arena of international politics."]', 'B2', '["arts","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (530, 'en', 'aspiration', 'noun', '/ˌæspəˈreɪʃn/', '志向；抱负', 'a strong desire to have or achieve something', '["She has aspirations of becoming a doctor.","The course helps students explore their career aspirations."]', 'B2', '["work","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (531, 'en', 'assault', 'noun', '/əˈsɔːlt/', '攻击；袭击', 'a violent attack on a person; a strong criticism', '["The victim reported the assault to the police.","The army launched a major assault on the enemy position."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (532, 'en', 'assemble', 'verb', '/əˈsembl/', '集合；组装', 'to come together in a group; to put the parts of something together', '["The students assembled in the hall for the ceremony.","It took us two hours to assemble the new bookshelf."]', 'B2', '["daily-life","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (534, 'en', 'auction', 'noun', '/ˈɔːkʃn/', '拍卖', 'a public sale in which things are sold to the person who offers the most money', '["The painting was sold at auction for two million dollars.","They put the old house up for auction."]', 'B2', '["business","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (535, 'en', 'auto', 'noun', '/ˈɔːtoʊ/', '汽车', 'a car or motor vehicle', '["The auto industry is shifting toward electric vehicles.","He works at an auto repair shop near the highway."]', 'B2', '["technology","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (536, 'en', 'autonomy', 'noun', '/ɔːˈtɑːnəmi/', '自主权；自治', 'the freedom for a country, region, or organization to govern itself', '["The university enjoys a high degree of autonomy.","The region has been fighting for greater autonomy from the central government."]', 'B2', '["politics","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (537, 'en', 'aviation', 'noun', '/ˌeɪviˈeɪʃn/', '航空', 'the designing, building, and flying of aircraft', '["She has worked in the aviation industry for over twenty years.","Aviation safety has improved greatly in recent decades."]', 'B2', '["travel","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (538, 'en', 'ballot', 'noun', '/ˈbælət/', '选票；投票', 'the system of voting in writing and usually in secret; a piece of paper for voting', '["The result of the ballot will be announced tomorrow.","Workers voted by secret ballot to go on strike."]', 'B2', '["politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (539, 'en', 'bankruptcy', 'noun', '/ˈbæŋkrʌptsi/', '破产', 'the state of being unable to pay what you owe', '["The company filed for bankruptcy after years of losses.","Personal bankruptcy can take years to recover from."]', 'B2', '["business","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (540, 'en', 'barrel', 'noun', '/ˈbærəl/', '桶；枪管', 'a large round container with flat ends, used for storing liquids', '["Oil prices rose to $80 per barrel last month.","The wine is aged in oak barrels for two years."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (541, 'en', 'benchmark', 'noun', '/ˈbentʃmɑːrk/', '基准；标准', 'a standard or point of reference against which things can be compared', '["The company''s performance is a benchmark for the whole industry.","We need to set clear benchmarks for measuring progress."]', 'B2', '["business","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (542, 'en', 'betray', 'verb', '/bɪˈtreɪ/', '背叛；泄露', 'to hurt somebody who trusts you by not being loyal; to reveal a secret', '["He felt betrayed when his best friend lied to him.","Her face betrayed no sign of emotion."]', 'B2', '["relationships","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (543, 'en', 'biography', 'noun', '/baɪˈɑːɡrəfi/', '传记', 'the story of a person''s life written by somebody else', '["She is writing a biography of the famous scientist.","I enjoy reading biographies of historical figures."]', 'B2', '["arts","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (544, 'en', 'blend', 'verb', '/blend/', '混合；融合', 'to mix two or more things together', '["Blend the butter and sugar together until smooth.","The building blends well with the older houses around it."]', 'B2', '["daily-life","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (545, 'en', 'boast', 'verb', '/boʊst/', '吹嘘；拥有', 'to talk too proudly about something you have or can do', '["He likes to boast about his exam results.","The hotel boasts a beautiful garden and swimming pool."]', 'B2', '["communication","emotions"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (547, 'en', 'boundary', 'noun', '/ˈbaʊndəri/', '边界；界限', 'a real or imagined line that marks the limits of something', '["The river forms the boundary between the two countries.","It is important to set clear boundaries in any relationship."]', 'B2', '["politics","relationships"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (549, 'en', 'breed', 'verb', '/briːd/', '繁殖；培育', 'to keep animals or plants in order to produce young ones; to cause something', '["The farm breeds horses for racing.","Poverty and unemployment can breed crime."]', 'B2', '["environment","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (550, 'en', 'broadcast', 'verb', '/ˈbrɔːdkæst/', '广播；播放', 'to send out programmes on television or radio', '["The match will be broadcast live on television.","The radio station broadcasts news every hour."]', 'B2', '["communication","technology"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (551, 'en', 'bureau', 'noun', '/ˈbjʊroʊ/', '局；办事处', 'an office or organization that provides information or services', '["The travel bureau can help you plan your trip.","He works at the Federal Bureau of Investigation."]', 'B2', '["politics","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (553, 'en', 'canal', 'noun', '/kəˈnæl/', '运河；水渠', 'a long narrow stretch of water that has been made for boats to travel along', '["The canal connects the two rivers.","We took a boat ride along the old canal in the city."]', 'B2', '["travel","environment"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (555, 'en', 'casualty', 'noun', '/ˈkæʒuəlti/', '伤亡人员；受害者', 'a person who is killed or injured in a war or an accident', '["There were many casualties in the earthquake.","The first casualty of the budget cuts was the arts program."]', 'B2', '["health","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (556, 'en', 'catalog', 'noun', '/ˈkætəlɔːɡ/', '目录；产品清单', 'a complete list of items arranged in order; a book with pictures of goods for sale', '["You can order from the online catalog.","The library has a digital catalog of all its books."]', 'B2', '["business","education"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (557, 'en', 'cater', 'verb', '/ˈkeɪtər/', '迎合；提供餐饮', 'to provide food and drinks for an event; to provide what somebody needs', '["The hotel caters for business travelers and tourists.","The menu caters to people with different dietary needs."]', 'B2', '["business","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (558, 'en', 'caution', 'noun', '/ˈkɔːʃn/', '谨慎；警告', 'care that you take to avoid danger or mistakes', '["You should proceed with caution when making big decisions.","The police issued a caution about driving in the heavy rain."]', 'B2', '["daily-life","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (559, 'en', 'cease', 'verb', '/siːs/', '停止；终止', 'to stop happening or existing; to stop doing something', '["The company ceased trading last month.","The noise ceased as soon as the teacher entered the room."]', 'B2', '["daily-life","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (562, 'en', 'civic', 'adjective', '/ˈsɪvɪk/', '公民的；市政的', 'connected with the people who live in a town or city; connected with citizenship', '["Voting is an important civic duty.","The mayor opened the new civic center last week."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (564, 'en', 'clash', 'noun', '/klæʃ/', '冲突；碰撞', 'a short fight between two groups of people; a strong disagreement', '["There was a clash between police and protesters.","There is often a clash between work demands and family life."]', 'B2', '["society","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (568, 'en', 'collaborate', 'verb', '/kəˈlæbəreɪt/', '合作；协作', 'to work together with somebody to produce or achieve something', '["The two universities will collaborate on the research project.","She collaborated with a local artist to design the poster."]', 'B2', '["work","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (569, 'en', 'collision', 'noun', '/kəˈlɪʒn/', '碰撞；冲突', 'an accident in which two vehicles or people crash into each other', '["Two cars were involved in a collision on the highway.","The collision between the two ships caused major damage."]', 'B2', '["travel","daily-life"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (570, 'en', 'colonial', 'adjective', '/kəˈloʊniəl/', '殖民的；殖民地的', 'connected with or belonging to a country that controls another country', '["The country gained independence from its colonial rulers.","Many colonial buildings still stand in the old part of the city."]', 'B2', '["politics","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (573, 'en', 'commissioner', 'noun', '/kəˈmɪʃənər/', '专员；委员', 'the head of a government department or other organization', '["The police commissioner held a press conference.","The EU commissioner spoke about new trade regulations."]', 'B2', '["politics","law"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (575, 'en', 'compelling', 'adjective', '/kəmˈpelɪŋ/', '引人注目的；令人信服的', 'so interesting or exciting that you have to pay attention', '["The documentary tells a compelling story about climate change.","She made a compelling argument for changing the policy."]', 'B2', '["communication","arts"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (580, 'en', 'component', 'noun', '/kəmˈpoʊnənt/', '组成部分；零件', 'one of several parts of which something is made', '["Exercise is a key component of a healthy lifestyle.","The factory makes electronic components for computers."]', 'B2', '["technology","science"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (582, 'en', 'comprise', 'verb', '/kəmˈpraɪz/', '包含；由……组成', 'to have something as parts or members; to be those parts or members', '["The committee comprises ten members from different departments.","Women comprise about 45 percent of the total workforce."]', 'B2', '["work","society"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (584, 'en', 'concession', 'noun', '/kənˈseʃn/', '让步；特许权', 'something that you agree to do or give to somebody in order to end an argument', '["Both sides had to make concessions to reach an agreement.","The government made no concessions to the protesters."]', 'B2', '["politics","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (591, 'en', 'consistency', 'noun', '/kənˈsɪstənsi/', '一致性；稳定性', 'the quality of always behaving or performing in a similar way', '["Consistency is the key to improving your language skills.","There was a lack of consistency in the way the rules were applied."]', 'B2', '["education","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (592, 'en', 'conspiracy', 'noun', '/kənˈspɪrəsi/', '阴谋；密谋', 'a secret plan by a group of people to do something illegal or harmful', '["He was found guilty of conspiracy to commit fraud.","Many people believe conspiracy theories about the event."]', 'B2', '["law","politics"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (594, 'en', 'consultation', 'noun', '/ˌkɑːnslˈteɪʃn/', '咨询；磋商', 'a meeting with an expert to get advice; a discussion before a decision is made', '["The doctor offers a free consultation for new patients.","The decision was made after consultation with all team members."]', 'B2', '["health","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (596, 'en', 'contend', 'verb', '/kənˈtend/', '竞争；主张', 'to compete against somebody to gain something; to say that something is true', '["Three candidates are contending for the leadership position.","She contends that the new policy is unfair to workers."]', 'B2', '["politics","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (597, 'en', 'controversial', 'adjective', '/ˌkɑːntrəˈvɜːrʃl/', '有争议的', 'causing a lot of angry public discussion and disagreement', '["The decision to close the school was highly controversial.","The politician made several controversial statements during the debate."]', 'B2', '["politics","communication"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (598, 'en', 'convene', 'verb', '/kənˈviːn/', '召集；集合', 'to arrange for people to come together for a formal meeting', '["The president convened an emergency meeting of the cabinet.","The committee will convene again next Monday."]', 'B2', '["politics","work"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (599, 'en', 'conversion', 'noun', '/kənˈvɜːrʒn/', '转换；改变', 'the process of changing something from one form, use, or system to another', '["The conversion of the old factory into apartments took two years.","The app handles currency conversion automatically."]', 'B2', '["technology","business"]');
INSERT OR IGNORE INTO words (id, language_id, word, pos, phonetic, definition_native, definition_target, examples, level, topics) VALUES (600, 'en', 'coordination', 'noun', '/koʊˌɔːrdɪˈneɪʃn/', '协调；配合', 'the act of organizing people or things so that they work together effectively', '["The project requires close coordination between all departments.","Good hand-eye coordination is important for playing sports."]', 'B2', '["work","health"]');

-- Passages (37 entries)
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (1, 'en', 'The Quiet Revolution in School Lunches', 'A nationwide campaign to transform school meals has gained momentum in recent months. Nutritionists emphasize that children''s diets have a profound impact on their cognitive development and long-term health. Several cities have begun to integrate fresh, locally grown produce into cafeteria menus, replacing processed food with wholesome alternatives. The initiative has not been without obstacles. Budget constraints forced some districts to negotiate with local farmers for affordable supplies. Critics dismiss the effort as merely symbolic, but early indicators suggest otherwise. Schools that adopted the program report a notable decline in student absences and a surge in concentration levels. Advocates insist that investing in children''s nutrition is not a trivial matter — it is a fundamental obligation. If the trend continues to thrive, it could reshape how an entire generation thinks about food.', 'B2', 'health', 'news');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (2, 'en', 'Rising Seas Threaten Pacific Island Nations', 'Scientists have detected an alarming rise in sea levels across the Pacific, and the consequences for island communities are becoming impossible to overlook. Coastal erosion has already displaced hundreds of families from their homes. Governments are scrambling to allocate emergency funds, but the deficit between what is needed and what is available remains vast. International organizations have pledged support, yet their response has been insufficient so far. Local leaders confront a painful reality: some islands may vanish entirely within decades. The situation demands a comprehensive strategy that goes beyond temporary shelter. Experts urge wealthy nations to uphold their climate commitments and acknowledge that these communities bear a disproportionate burden of a crisis they did not create. The stakes are tremendous — not just for the Pacific, but for global solidarity.', 'B2', 'environment', 'news');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (3, 'en', 'What I Learned from a Year Without Shopping', 'Last January, I made a pledge to stop buying anything I did not strictly need for twelve months. The impulse to shop had become a persistent habit, and I wanted to confront it honestly. The first few weeks were intense. I would linger in front of store windows, resisting temptation. Gradually, something shifted. I began to perceive my relationship with objects differently. Most of what I owned was surplus — things acquired out of boredom rather than necessity. By summer, I felt a profound sense of freedom. I redirected the money I saved toward experiences: hiking trips, cooking classes, and long dinners with friends. The experiment did not transform me into a minimalist overnight, but it shed light on a subtle truth. Happiness rarely comes from possession. It stems from connection, curiosity, and the patience to sit with discomfort until it passes.', 'B2', 'daily-life', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (4, 'en', 'My Grandmother''s Kitchen', 'My grandmother''s kitchen was a modest space — barely enough room for two people to stand side by side. Yet everything that mattered in our family seemed to originate there. She would rise before dawn, and the aroma of fresh bread would linger throughout the house by the time we woke. Her recipes were never written down. She relied on instinct and decades of practice, adjusting flavours with a swift confidence I have never witnessed in anyone else. When I was an adolescent, I dismissed her cooking as ordinary. It was only after she passed away that I grasped how remarkable those meals truly were. Each dish carried traces of her heritage and the traditions of her ancestors. Now, when I attempt to recreate her soup, the result is merely adequate. But the ritual itself sustains me — it is an intimate thread connecting past and present, a reminder that love often manifests in the simplest gestures.', 'B2', 'relationships', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (5, 'en', 'Tbilisi: Where East Meets West in Every Bite', 'Tbilisi greets visitors with a landscape of contradictions: crumbling balconies beside sleek glass towers, ancient churches overlooking vibrant night markets. The city''s charm is not subtle — it seizes you from the moment you step into its steep, winding streets. I spent three days navigating the old town, drawn by the scent of freshly baked bread and the sound of church bells. The food scene is outstanding. Georgian cuisine blends bold spices with modest ingredients to produce dishes of sheer beauty. At a tiny restaurant near the river, a woman served me a meal that exceeded every expectation. I tried to convey my appreciation, but language was a barrier. She smiled and gestured toward the kitchen, as if to say the food would speak for itself. Tbilisi taught me that authentic travel is not about ticking off landmarks — it is about surrendering to the rhythm of an unfamiliar place.', 'B2', 'travel', 'travel');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (6, 'en', 'Walking the Camino: Six Hundred Miles of Thinking', 'I set out on the Camino de Santiago with a heavy backpack and a vague idea of what lay ahead. By the third day, my limbs ached and my motivation had begun to shrink. A fellow walker — a retired nurse from Denmark — noticed my struggle and offered simple guidance. Walk slowly, she said, and do not anticipate what comes next. Her advice was profound in its simplicity. Over the following weeks, the landscape shifted from green hills to dry plains and then to steep mountain passes. Each morning I would emerge from a small shelter, stiff and sore but increasingly alert. The solitude stripped away the noise of everyday life and exposed something underneath: a keen desire to live with greater intention. By the time I reached Santiago, I had undergone a quiet transformation. The journey did not provide answers, but it taught me to tolerate uncertainty — and that, I believe, was the whole point.', 'B2', 'travel', 'travel');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (7, 'en', 'Why Remote Work Is Not the Future — It Is the Present', 'The debate over remote work has dragged on for years, yet the evidence is now overwhelming. Productivity does not decline when people work from home — in many cases it soars. Companies that insist on mandatory office attendance are clinging to an outdated norm that prioritises visibility over output. The workforce has evolved, and rigid policies merely provoke resentment. Workers value autonomy and the flexibility to integrate professional and personal responsibilities. Opponents argue that collaboration suffers without physical proximity, but this perspective overlooks the sophisticated tools now available for virtual interaction. Commuting wastes time, drains energy, and contributes to carbon emissions. From a strategic standpoint, offering remote options helps firms attract qualified talent from a broader pool. The transition will not be swift for every industry, but the underlying trend is undeniable. Organizations that resist this shift do so at their own peril.', 'B2', 'work', 'opinion');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (8, 'en', 'Universities Should Scrap Traditional Exams', 'Every year, millions of students endure weeks of intense revision only to sit in a silent hall and pour their knowledge onto paper within a rigid time limit. This model of assessment is not merely outdated — it is actively harmful. Research consistently demonstrates that high-stakes exams trigger anxiety, distort learning, and reward memorisation over genuine understanding. A persistent myth holds that exams are the sole valid measure of competence. In reality, coursework, group projects, and oral presentations yield a far more comprehensive picture of a student''s capability. Several prestigious institutions have already adopted alternative methods and report outstanding results. Critics contend that abolishing exams would undermine standards, but the evidence does not support this claim. If universities truly aspire to nurture critical thinking, they must be willing to modify how they evaluate it. Clinging to tradition for its own sake is not rigour — it is intellectual laziness.', 'B2', 'education', 'opinion');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (9, 'en', 'The Surgeon Who Paints', 'Dr Karim had spent two decades operating on hearts. His hands were steady, his reputation outstanding, and his schedule relentless. One evening, after a procedure that lasted nine hours, he sat alone in the hospital car park, unable to move. The strain of years without rest had finally caught up with him. A colleague suggested he find an outlet beyond medicine. On impulse, Karim enrolled in a weekend painting class. He felt awkward holding a brush — his precise, surgical instincts were useless on canvas. The instructor told him to stop trying to control the outcome and simply let the colours interact. Weeks passed. The paintings were terrible at first, but something subtle began to shift. Karim noticed his breathing slowed when he painted. The tension in his shoulders would ease. He never became a notable artist, but art gave him what surgery could not — permission to be imperfect. He still operates five days a week, but now his weekends belong to colour, silence, and the sheer pleasure of making something with no purpose beyond itself.', 'B2', 'arts', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (10, 'en', 'The Night the Lights Went Out', 'The blackout struck without warning on a Friday evening, plunging the entire district into darkness. At first there was chaos — car horns, shouts, the sound of things falling. But within an hour, something unexpected happened. Neighbours who had never spoken began to interact. Someone lit candles on their front steps; another dragged a barbecue onto the pavement and started cooking for anyone who was hungry. Children ran through the streets, thrilled by the novelty of a world without screens. An elderly man told stories on his porch while teenagers listened, genuinely fascinated. The atmosphere was intense yet warm, a peculiar blend of emergency and celebration. Power was restored by midnight, and the neighbourhood promptly returned to its routine. But for those few hours, the community had witnessed what life looks like when distractions vanish — and many felt a keen longing to preserve that feeling somehow.', 'B2', 'society', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (11, 'en', 'A Conversation with Chef Amara Osei', 'When asked how she overcame setbacks early in her career, Chef Amara Osei pauses before answering. Growing up in Accra, she had always felt a keen appetite for cooking, but the culinary industry was dominated by men who dismissed her ambitions. Rather than conform to expectations, she chose to pursue her goal with fierce determination. She trained in Paris, where she endured harsh criticism from instructors who doubted her potential. Looking back, she says those experiences were invaluable. They taught her to distinguish between constructive feedback and mere prejudice. Today, Osei runs three restaurants across West Africa, each one a tribute to indigenous ingredients and traditional techniques. Her philosophy is straightforward: use what the land provides, and never substitute quality for convenience. When asked about the widespread belief that African cuisine lacks sophistication, she responds sharply. The world is only just beginning to grasp the depth and diversity of what this continent offers, she says. And I intend to make sure they pay attention.', 'B2', 'daily-life', 'interview');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (12, 'en', 'How Noise-Cancelling Headphones Work', 'Noise-cancelling headphones seem almost magical, but the underlying mechanism is surprisingly straightforward. A tiny microphone on the outside of each ear cup detects incoming sound waves. A processor then generates a precisely opposite wave — what engineers call an anti-phase signal. When the two waves interact, they cancel each other out, producing near silence. This phenomenon is known as destructive interference. The technology works best on consistent, low-frequency sounds such as engine hum or air conditioning. It is less effective against sudden, random noises like speech or a door slamming. Premium models incorporate multiple microphones and sophisticated algorithms to adapt to changing environments in real time. The innovation has been a breakthrough for frequent travellers, office workers, and anyone who needs to concentrate in noisy settings. However, experts caution that prolonged use at high volume can still inflict damage on hearing. Like any tool, the value lies not in the technology itself but in how wisely we choose to use it.', 'B2', 'technology', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (101, 'en', 'Small Changes, Big Results', 'Most people know that a healthy life requires good habits, but turning that knowledge into action is harder than it sounds. The key is to start with moderate changes rather than dramatic ones. For example, walking for twenty minutes each day can enhance your energy levels and help you sleep better at night. You do not need to follow a strict plan. Even small, consistent steps lead to real progress over time. Many doctors point out that chronic tiredness is often linked to poor sleep and a lack of movement. If you allow adequate time for rest each evening, you will notice a steady decline in stress. The duration of each healthy habit matters less than doing it every single day. What counts is showing up, again and again, until the new behaviour feels natural.', 'B1', 'health', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (102, 'en', 'Making the Most of a Tiny Flat', 'When Mei moved into her new flat, she could barely fit a bed and a desk in the same room. The interior felt dark and cramped. Her first impulse was to buy more furniture, but she quickly realised that would only make things worse. Instead, she decided to eliminate everything she did not use. Old clothes, spare cables, books she would never read again — all of it went into boxes for charity. She found subtle ways to create space: a mirror on the wall made the room look wider, and a tall shelf replaced the stiff old bookcase that had blocked the window. Within a week, her surplus of clutter had vanished. The flat was still small, but it finally felt like home. Mei learned that sometimes you gain more by removing things than by adding them. A squeeze on space can actually push you toward smarter choices.', 'B1', 'daily-life', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (103, 'en', 'The First Week', 'On Monday morning, Priya arrived at the office thirty minutes early. She did not want to seem awkward on her first day. A colleague named Sam showed her around and explained how things worked. The pace was overwhelming at first — so many names, so many rules. Priya felt keen to do well, but she worried about making mistakes. On Wednesday she missed a deadline because she had not understood the task properly. Her manager did not seem angry, though. Instead, he offered clear guidance and told her that the outcome of the first week did not define her future at the company. By Friday, Priya felt calmer. She realised that no one expected her to impress everyone straight away. Settling in takes time, and asking for help is not a weakness — it is a sign of good judgement.', 'B1', 'work', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (104, 'en', 'How a Search Engine Finds What You Need', 'When you type a question into a search engine, the answer appears in less than a second. But what happens behind the screen? First, small programs crawl across billions of web pages to detect new or updated content. They store this information in a huge index, much like a library catalogue. When you search, the engine does not look at every page on the internet. Instead, it checks the index and uses a logical set of rules to decide which results match your words most precisely. An indicator of quality is how many other trusted pages link to a result. The system also tracks how users interact with the results — if people click on a page and stay, that is a good sign. Thanks to constant innovation, search engines now handle random spelling mistakes and even understand what you mean when your words are not exact.', 'B1', 'technology', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (105, 'en', 'A Weekend Away Without the Stress', 'Planning a short trip does not have to be complicated. Start by choosing a nearby destination that you can reach in two or three hours. You do not need a passport or an expensive flight — sometimes the best places are close to home. Before you go, check a map and learn how to navigate the area on foot or by bus. If the landscape includes steep hills, pack comfortable shoes. Read a few reviews to find an outstanding place to eat, and look for authentic local dishes rather than tourist restaurants. The biggest obstacle most travellers face is trying to do too much. A weekend is not long enough to overcome exhaustion from a packed schedule. Pick two or three things you truly want to see, and leave the rest for another visit. The goal is to return home feeling rested, not more tired than when you left.', 'B1', 'travel', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (106, 'en', 'The Friends We Forget to Call', 'Old friendships are easy to neglect. Life gets busy, and before you know it, months have passed since you last spoke. The problem is rarely a lack of loyalty — it is simply that daily tasks take over. Yet the people who knew us years ago hold something valuable: a mutual understanding that newer friends may not share. Keeping in touch does not require a grand gesture. A short message, a photo from a place you both remember, or a quick voice call can be enough. What matters is that the effort feels genuine, not forced. Some people linger in our thoughts without us ever reaching out. There is a common assumption that they are too busy or that too much time has passed. But most of the time, they are waiting for the same thing we are — a simple sign that somebody still cares. Do not let an old friendship fade. Embrace the awkwardness of reconnecting, and you may find that the bond is stronger than you thought.', 'B1', 'relationships', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (107, 'en', 'Study Smarter, Not Harder', 'Many students believe that spending more hours at their desk will lead to better exam results. However, research shows that the way you study matters more than the time you spend. First, set a clear deadline for each topic and stick to it. Break large subjects into smaller parts and tackle them one by one. Taking short breaks helps your brain stay fresh and productive. Another useful approach is to evaluate what you already know before revising new material. This helps you focus your energy where it is truly needed. Some students overlook the importance of sleep, but resting well the night before an exam is crucial. Finally, do not neglect practice tests. They demonstrate how well you have prepared and highlight areas that still need attention. With discipline and a logical plan, any student can improve their results.', 'B1', 'education', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (108, 'en', 'Small Steps to a Greener Home', 'Recycling at home does not have to be difficult. Start with the basics: separate paper, plastic, and glass into different bins. Even this small gesture can make a significant difference over time. Many people overlook items like batteries and old electronics, which should never go in regular rubbish. Check if your local area has a collection point for these. Another way to help the environment is to reduce food waste. Plan your meals for the week and buy only what you need. Leftover vegetables can be used to make soup rather than being thrown away. Choosing sustainable products is also a practical step. Look for items with less packaging or packaging that can be recycled readily. These changes may seem subtle, but when an entire community adopts them, the impact is tremendous.', 'B1', 'environment', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (109, 'en', 'The Art of Writing a Good Email', 'In today''s world, email is one of the most common ways to communicate at work. Yet many people struggle to write messages that are clear and effective. The first step is to think about your reader. What do they need to know? Keep your sentences short and avoid vague language that could confuse them. A strong subject line helps the reader grasp the purpose of your email immediately. If you are making a request, state it clearly near the beginning. It is also important to convey a polite and professional tone, even when the topic is difficult. Before you click send, take a moment to revise your draft. Check for spelling mistakes and make sure the message is not too long. A well-written email can enhance your reputation and strengthen your relationships with colleagues. Good communication is a valuable skill that improves steadily with practice.', 'B1', 'communication', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (110, 'en', 'The Painting That Changed Everything', 'Last spring, my friend Sara dragged me to the city art museum. I had never been particularly keen on paintings, and I expected to be bored. The first few rooms were filled with landscapes and portraits that meant little to me. Then we turned a corner and I encountered a large painting of a storm at sea. The colours were intense — dark blues and greens crashing against each other. I could almost feel the wind. I stood there for several minutes, unable to move. Something about it triggered an emotion I could not name. Sara noticed my reaction and smiled. She said art does not need to be logical to be meaningful. That single painting transformed my afternoon into something truly memorable. I have been back to the museum three times since then, each visit revealing subtle details I missed before.', 'B1', 'arts', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (111, 'en', 'Why Volunteering Matters More Than You Think', 'Volunteering is often seen as something people do in their spare time to feel good about themselves. While that is partly true, the benefits go much deeper. When you dedicate a few hours each week to helping others, you gain skills that are hard to acquire elsewhere. Working at a food bank or a shelter teaches patience, teamwork, and coordination. It can also shift your perspective on life. Many volunteers say they become more aware of the challenges their neighbours face. This exposure to different situations helps them develop genuine sympathy for others. Communities that encourage volunteering tend to be stronger and more connected. The impact is not merely personal — it is widespread. If you are looking for a way to make your local area a better place, consider giving your time. Even a small commitment can yield remarkable results.', 'B1', 'society', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (112, 'en', 'When Stress Takes Over', 'Everyone feels stressed from time to time, but when the pressure becomes ongoing, it can seriously affect your health. The strain of too many responsibilities may lead to poor sleep, headaches, and difficulty concentrating. Recognising the early signs is crucial. Pay attention to how your body reacts when you feel overwhelmed. Tense shoulders, a tight stomach, and a racing heart are all common indicators. Once you identify the triggers, you can take steps to manage them. Simple habits like walking outdoors, writing in a journal, or talking to a trusted friend can make a profound difference. It is also important not to neglect your basic needs — eating well, sleeping enough, and taking breaks throughout the day. Learning to cope with stress is not about eliminating it entirely. It is about building tolerance so that difficult moments do not define your life.', 'B1', 'emotions', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (113, 'en', 'How Weather Forecasts Are Made', 'Every morning, millions of people check the weather forecast before leaving home. But how do experts predict what the sky will do? The process begins with data collection. Weather stations, satellites, and special balloons detect changes in temperature, wind, and air pressure. This information is fed into powerful computers that use complex models to anticipate future conditions. The computers generate predictions for the next few hours, days, and even weeks. However, forecasts become less accurate the further ahead they look. A five-day outlook is generally reliable, but anything beyond that is increasingly vague. Scientists are constantly working to enhance these models by integrating new technology. Despite the limitations, modern forecasting has undergone a tremendous transformation over the past few decades. It saves lives by giving people sufficient time to prepare for storms and other severe weather events.', 'B1', 'science', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (114, 'en', 'A Weekend Idea That Grew', 'It started as a small side project on Saturday mornings. My colleague Tom had always been keen on baking, and he began selling cakes at the local market. At first, sales were modest. He barely made enough to cover the cost of ingredients. But Tom was patient and dedicated. He listened to feedback, modified his recipes, and steadily improved the quality. Within a few months, a surge in orders forced him to rethink his approach. He launched a simple website and started taking orders online. The transition from hobby to small business was not easy. Tom had to negotiate with suppliers and tackle problems he had never anticipated. Yet the setbacks only made him more determined. Today, his bakery delivers across the city. When I asked him what made the difference, he said it was the commitment to keep going, even when the outcome was uncertain.', 'B1', 'business', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (115, 'en', 'Finding Joy in the Kitchen', 'Learning to cook can feel overwhelming at first. There are so many recipes, techniques, and ingredients to learn about. The key is to start simple. Pick a dish you already enjoy eating and try to make it at home. Do not worry if the outcome is not perfect — even experienced cooks make mistakes. The crucial thing is to keep trying. Gradually, you will develop an instinct for flavours and textures. One of the most rewarding aspects of cooking is the chance to experiment. Substitute one ingredient for another and see what happens. Add a herb you have never used before. Each attempt enhances your skills and builds your confidence. Cooking also provides a wonderful way to interact with family and friends. Preparing a meal together can transform an ordinary evening into something special. With patience and a keen appetite for learning, anyone can become a competent home cook.', 'B1', 'daily-life', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (116, 'en', 'How a Screen Draws a Picture', 'When you open a web page, your computer does a lot of work behind the scenes. The rendering engine reads the code and turns it into what you see on screen. First, it builds a tree of all the elements on the page. Then it works out where each element should go and how big it should be. This is a fundamental step because even a small mistake can make the whole page look wrong. Next, the engine paints the colours and shapes onto the screen. Each component of the page goes through this process in a linear order. Modern engines are sophisticated enough to skip parts that have not changed. Understanding this mechanism helps developers write faster, smoother websites. Although users rarely think about it, the output they see is the result of many careful steps working together.', 'B1', 'technology', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (117, 'en', 'Tracking Down a Rendering Bug', 'Last week, I noticed that a button on our app was not showing in the right place. It only happened on certain screen sizes, which made it hard to detect. I started by checking the recent code changes to trace the problem. After an hour of reading through files, I found that a small update had triggered the layout to break. The underlying cause was a missing value in the style rules. It was a minor issue, but it had a significant effect on how the page looked. I felt some frustration at first, but staying patient helped me think clearly. Once I fixed the code, I tested it thoroughly on different devices. The bug was gone. My colleague said she had overlooked the same problem earlier. It reminded me that even small details can have a tremendous impact on quality.', 'B1', 'technology', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (118, 'en', 'Learning from a Code Review', 'Code review is a common practice in software teams. When a developer finishes a piece of work, a colleague looks at the code before it goes live. The goal is to assess the quality and find anything that might cause problems later. Good reviewers do not merely point out mistakes. They also explain why a certain approach is better. This helps the whole team improve steadily over time. It can feel awkward to have someone inspect your work, but most people learn to see it as a chance to grow. A thorough review often catches issues that testing alone would miss. It is important to convey your comments in a kind and clear way. When done well, code review builds trust and leads to more consistent output across the project.', 'B1', 'work', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (119, 'en', 'A Productive Team Meeting', 'Every Monday, our team holds a short meeting to talk about the week ahead. The lead engineer starts by giving an outline of the main tasks. Then each person shares what they are working on and any obstacles they face. Last Monday, two developers had different ideas about how to solve a rendering problem. One wanted to modify the existing code, while the other suggested writing it from scratch. The discussion was intense at times, but everyone listened carefully. In the end, the team reached a consensus and agreed to try the first approach. These meetings facilitate better communication and help us anticipate problems before they grow. I have noticed that when people feel heard, they become more productive and keen to contribute.', 'B1', 'communication', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (120, 'en', 'Making the App Run Faster', 'Performance is a crucial aspect of any application. If a page takes too long to load, users will leave. The first step is to evaluate where the slowness comes from. Developers use special tools to measure how long each part of the code takes to run. Sometimes the problem is that the app does too many things simultaneously. Other times, a single slow function can become an obstacle for the whole system. One common strategy is to minimize the amount of work the browser has to do on each frame. Another is to eliminate unnecessary calculations that happen again and again. Setting a clear benchmark helps the team track progress over time. Even a swift improvement of a few milliseconds can make the experience feel much smoother for the user.', 'B1', 'technology', 'explainer');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (121, 'en', 'Racing Against the Deadline', 'We had two weeks to finish the new feature, but halfway through, a major setback slowed us down. The design changed, and we had to redo a large part of the work. The strain on the team was obvious. Some people stayed late every night, and the atmosphere became tense. Our manager tried to allocate extra help, but it was hard to find people who understood the code. I felt a growing anxiety about whether we would finish on time. Nevertheless, we kept going and split the remaining tasks into smaller pieces. Each person was dedicated to one part and worked hard. On the last day, we submitted the feature just before the deadline. The outcome was not perfect, but it was good enough to launch. The experience taught me that patience and teamwork matter most under pressure.', 'B1', 'work', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (122, 'en', 'Solving a Hard Problem Together', 'Our rendering engine had a persistent bug that no one could fix alone. Images would flicker on screen whenever the user scrolled quickly. Three of us decided to collaborate and tackle the issue as a group. We started by listing every possible cause and then testing each assumption one by one. It took two full days of careful work. At one point, we discovered that the engine was trying to draw the same image twice in the same frame. The solution was to add a check that would prevent this from happening. It was a breakthrough moment for the team. Working alongside each other helped us grasp the problem from different angles. I learned that some obstacles are too complex for one person and that genuine teamwork, where people cooperate openly, can yield remarkable results.', 'B1', 'work', 'story');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (123, 'en', 'Writing Clear Technical Documentation', 'Good documentation is just as important as good code. When a new developer joins the team, they need to grasp how the system works without asking too many questions. A comprehensive guide saves time and reduces confusion. The first step is to outline the main parts of the system and how they connect. Use simple language and avoid vague descriptions that could be interpreted in different ways. It helps to include examples that demonstrate how each feature behaves. Many teams neglect documentation because they are busy writing code. However, this tendency leads to problems when someone leaves or when the project grows. Keeping your documents up to date requires ongoing effort and discipline. A well-written guide can transform a confusing codebase into one that any competent developer can understand readily.', 'B1', 'communication', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (124, 'en', 'Cleaning Up Old Code', 'Refactoring means changing the structure of code without changing what it does. Over time, software projects accumulate layers of quick fixes that make the code harder to read. A developer may encounter functions that are too long or logic that is difficult to follow. The goal of refactoring is to make the code cleaner and easier to modify in the future. It is a fundamental practice that many teams overlook because the results are not immediately visible. However, neglecting it can trigger serious problems down the road. Before starting, it is important to have good tests so you can verify that nothing breaks. A rational approach is to refactor small sections at a time rather than rewriting everything at once. The subsequent code is usually simpler and more stable. Teams that dedicate time to refactoring find that new features become easier to implement.', 'B1', 'technology', 'essay');
INSERT OR IGNORE INTO passages (id, language_id, title, text, level, topic, genre) VALUES (125, 'en', 'Welcome to the Rendering Team', 'Last month, a new developer named Li joined our rendering team. She had just finished university and was keen to learn. On her first day, we gave her a comprehensive overview of the project and its framework. She asked many thoughtful questions, which showed that she was eager to grasp the details. Her manager paired her with a senior colleague who would provide guidance during the first few weeks. Li found the codebase overwhelming at first, but she adapted quickly. By the end of her second week, she had already submitted her first code change. The team acknowledged her effort and gave her positive comments. Watching someone new integrate into the group reminded us all of how important it is to be patient and supportive. A welcoming atmosphere can transform a nervous newcomer into a dedicated team member.', 'B1', 'relationships', 'story');

